                                    </div>
                                    <p className="text-sm text-slate-500 dark:text-slate-400 capitalize">{friend.role}</p>
                                </div>
                                <div className="flex flex-shrink-0 items-center gap-1 opacity-0 group-hover:opacity-100 transition-opacity duration-300">
                                    <button 
