                const freshUser = auth.currentUser; 

                if (!freshUser) {
                    setFirebaseUser(null);
                    setAppUser(null);
                    setNotifications([]);
                    setToasts([]);
                    setShowLanding(true);
                    setIs404(false);
                    setAuthPage(null);
                    setAuthInitialMode('signin');
                    setAuthExiting(false);
                    setAuthLoading(false);
                    setIsInitialAuthLoading(false);
                    return;
