    const processMissedNotifications = useCallback(async () => {
        if (!appUser) return;
        const supabase = getSupabase();
        if (!supabase) return;

        try {
            const { data: missedNotifications, error } = await supabase
                .from('global_notifications')
                .select('*')
                .eq('to_email', appUser.email.toLowerCase());

            if (error) throw error;

            if (missedNotifications && missedNotifications.length > 0) {
                missedNotifications.forEach(notif => handleReceivedGlobalNotification(notif, true));

                const idsToDelete = missedNotifications.map(n => n.id);
                await supabase.from('global_notifications').delete().in('id', idsToDelete);
            } 
        } catch (err) {
            console.error("[Sync] Error fetching missed notifications:", err);
        }
    }, [appUser, handleReceivedGlobalNotification]);

    useEffect(() => {
        const supabase = getSupabase();
        if (!supabase || !appUser) return;

        const channel = supabase.channel(`global-notifications-for-${appUser.id}`)
          .on('postgres_changes', {
            event: 'INSERT',
            schema: 'public',
            table: 'global_notifications',
            filter: `to_email=eq.${appUser.email.toLowerCase()}`
          }, async (payload) => {
            handleReceivedGlobalNotification(payload.new, false); 
            await supabase!.from('global_notifications').delete().eq('id', payload.new.id);
          })
          .subscribe((status, err) => {
              if (status === 'SUBSCRIBED') {
                  processMissedNotifications();
              }
          });

        return () => {
            supabase.removeChannel(channel);
        };
    }, [appUser, handleReceivedGlobalNotification, processMissedNotifications]);

  const handleSendFriendRequest = useCallback(async (fromUser: User, toUserEmail: string) => {
    if (!appUserRef.current) return;

    // 1. Check if user exists
    const targetUser = allUsersRef.current.find(u => u.email === toUserEmail);
    if (!targetUser) {
        addNotification({ title: 'Error', message: 'User not found.', type: 'error' });
        return;
    }

    // 2. Validation
    if (targetUser.email === fromUser.email) {
        addNotification({ title: 'Error', message: "You can't add yourself.", type: 'error' });
        return;
    }
    if (targetUser.friends?.includes(fromUser.email)) {
        addNotification({ title: 'Info', message: "You are already friends.", type: 'info' });
        return;
    }
    if (targetUser.friend_requests?.includes(fromUser.email)) {
        addNotification({ title: 'Info', message: "Friend request already sent.", type: 'info' });
        return;
    }

    // 3. Update Target User
    const currentRequests = targetUser.friend_requests || [];
    const updatedRequests = [...currentRequests, fromUser.email];

    try {
        await updateUser(targetUser.email, { friend_requests: updatedRequests });

        // 4. Send Notification
        const notification: GlobalNotification = {
            id: crypto.randomUUID(),
            to: targetUser.email,
            from: {
                email: fromUser.email,
                name: fromUser.name,
                avatar: fromUser.avatar,
                role: fromUser.role
            },
            type: 'friend_request',
            title: 'New Friend Request',
            message: `${fromUser.name} sent you a friend request.`
        };
        await sendGlobalNotifications([notification]);

        addNotification({ title: 'Success', message: `Friend request sent to ${targetUser.name}.`, type: 'success' });
        logActivity('sent a friend request to', targetUser.name);

    } catch (error) {
        console.error("Failed to send friend request:", error);
        addNotification({ title: 'Error', message: "Failed to send request.", type: 'error' });
    }
  }, [addNotification, logActivity]);

