type ViewMode = 'year' | 'month' | 'week' | 'day';

const DAYS = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const MONTHS = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

// Mock Data Generator
const generateMockData = (year: number) => {
    const data: Record<string, number> = {};
    const startDate = new Date(year, 0, 1);
    const endDate = new Date(year, 11, 31);

    for (let d = new Date(startDate); d <= endDate; d.setDate(d.getDate() + 1)) {
        const dateStr = d.toISOString().split('T')[0];
        // Simulate random completion
        // 40% chance of 10/10, 30% chance of 5-9, 20% chance of 1-4, 10% chance of 0
        const rand = Math.random();
        let count = 0;
        if (rand > 0.6) count = 10;
        else if (rand > 0.3) count = Math.floor(Math.random() * 5) + 5; // 5-9
        else if (rand > 0.1) count = Math.floor(Math.random() * 4) + 1; // 1-4

        data[dateStr] = count;
    }
    return data;
};

const getCompletionColor = (count: number | undefined) => {
    if (count === undefined) return 'bg-slate-100 dark:bg-slate-800/50 text-transparent'; // Future/No data
    if (count === 10) return 'bg-emerald-500 text-white';
    if (count >= 7) return 'bg-indigo-500 text-white';
    if (count >= 4) return 'bg-amber-400 text-amber-900';
    if (count > 0) return 'bg-rose-400 text-white';
    return 'bg-slate-200 dark:bg-slate-700 text-slate-400'; // 0
};

const HabitCalendar: React.FC = () => {
    const [view, setView] = useState<ViewMode>('month');
    const [currentDate, setCurrentDate] = useState(new Date());

    // Memoize mock data for the current year
    const mockData = useMemo(() => generateMockData(currentDate.getFullYear()), [currentDate.getFullYear()]);

    const navigate = (direction: 'prev' | 'next') => {
        const newDate = new Date(currentDate);
        if (view === 'year') {
            newDate.setFullYear(newDate.getFullYear() + (direction === 'next' ? 1 : -1));
        } else if (view === 'month') {
            newDate.setMonth(newDate.getMonth() + (direction === 'next' ? 1 : -1));
        } else if (view === 'week') {
            newDate.setDate(newDate.getDate() + (direction === 'next' ? 7 : -7));
        } else {
            newDate.setDate(newDate.getDate() + (direction === 'next' ? 1 : -1));
        }
        setCurrentDate(newDate);
    };

    const goToToday = () => setCurrentDate(new Date());

    const formatDateKey = (date: Date) => date.toISOString().split('T')[0];

    // --- VIEW RENDERERS ---

    const renderYearView = () => {
        return (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-fade-in">
                {MONTHS.map((month, mIdx) => {
                    const firstDay = new Date(currentDate.getFullYear(), mIdx, 1);
                    const daysInMonth = new Date(currentDate.getFullYear(), mIdx + 1, 0).getDate();
                    const offset = firstDay.getDay();

                    return (
                        <button 
                            key={month} 
                            onClick={() => {
                                const newDate = new Date(currentDate);
                                newDate.setMonth(mIdx);
                                setCurrentDate(newDate);
                                setView('month');
                            }}
                            className="bg-white dark:bg-slate-800 rounded-xl p-4 border border-slate-200 dark:border-slate-700 hover:border-indigo-500 dark:hover:border-indigo-500 transition-colors text-left"
                        >
                            <h3 className="font-bold text-slate-800 dark:text-slate-100 mb-2">{month}</h3>
                            <div className="grid grid-cols-7 gap-1">
                                {Array.from({ length: offset }).map((_, i) => <div key={`empty-${i}`} />)}
                                {Array.from({ length: daysInMonth }).map((_, d) => {
                                    const dayDate = new Date(currentDate.getFullYear(), mIdx, d + 1);
                                    const key = formatDateKey(dayDate);
                                    const count = mockData[key];
                                    return (
                                        <div 
                                            key={d} 
                                            className={`aspect-square rounded-sm ${getCompletionColor(count)}`} 
                                            title={`${dateString(dayDate)}: ${count}/10`}
                                        />
                                    );
                                })}
                            </div>
                        </button>
                    );
                })}
            </div>
        );
    };

    const renderMonthView = () => {
        const year = currentDate.getFullYear();
        const month = currentDate.getMonth();
        const firstDay = new Date(year, month, 1);
        const daysInMonth = new Date(year, month + 1, 0).getDate();
        const offset = firstDay.getDay();

        // Get previous month overflow
        const prevMonthDays = new Date(year, month, 0).getDate();
        const prevMonthOverflow = Array.from({ length: offset }).map((_, i) => {
             return prevMonthDays - offset + i + 1;
        });

        // Current month days
        const days = Array.from({ length: daysInMonth }).map((_, i) => i + 1);

        // Next month overflow (to fill 6 rows * 7 cols = 42 cells)
        const totalCells = 42;
        const nextMonthOverflow = Array.from({ length: totalCells - (offset + daysInMonth) }).map((_, i) => i + 1);

        return (
            <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden animate-fade-in">
                {/* Header Row */}
                <div className="grid grid-cols-7 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
                    {DAYS.map(day => (
                        <div key={day} className="py-3 text-center text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400">
                            {day}
                        </div>
                    ))}
                </div>

                {/* Calendar Grid */}
                <div className="grid grid-cols-7 auto-rows-[100px] lg:auto-rows-[120px]">
                    {/* Previous Month Days */}
                    {prevMonthOverflow.map(day => (
                        <div key={`prev-${day}`} className="p-2 border-b border-r border-slate-100 dark:border-slate-700/50 bg-slate-50/50 dark:bg-slate-900/30 text-slate-400 dark:text-slate-600">
                            <span className="text-sm font-medium">{day}</span>
                        </div>
                    ))}

                    {/* Current Month Days */}
                    {days.map(day => {
                        const date = new Date(year, month, day);
                        const key = formatDateKey(date);
                        const count = mockData[key];
                        const isToday = key === formatDateKey(new Date());

                        return (
                            <div 
                                key={`curr-${day}`} 
                                onClick={() => { setCurrentDate(date); setView('day'); }}
                                className={`group p-2 border-b border-r border-slate-100 dark:border-slate-700/50 relative hover:bg-indigo-50 dark:hover:bg-indigo-900/10 cursor-pointer transition-colors ${isToday ? 'bg-indigo-50/50 dark:bg-indigo-900/20' : ''}`}
                            >
                                <div className="flex justify-between items-start">
                                    <span className={`text-sm font-bold ${isToday ? 'bg-indigo-600 text-white w-6 h-6 flex items-center justify-center rounded-full' : 'text-slate-700 dark:text-slate-300'}`}>
                                        {day}
                                    </span>
                                    {count !== undefined && (
                                        <span className={`text-[10px] font-bold px-1.5 py-0.5 rounded ${getCompletionColor(count)} bg-opacity-20 text-current`}>
                                            {Math.round((count / 10) * 100)}%
                                        </span>
                                    )}
                                </div>

                                {count !== undefined && (
                                    <div className="mt-3 space-y-1">
                                         {/* Mock habit bars */}
                                         <div className="h-1.5 w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                                             <div className={`h-full ${getCompletionColor(count)}`} style={{ width: `${(count/10)*100}%` }}></div>
                                         </div>
                                         <p className="text-[10px] text-slate-500 dark:text-slate-400 text-right">{count}/10 Done</p>
                                    </div>
                                )}
                            </div>
                        );
                    })}

                    {/* Next Month Days */}
                    {nextMonthOverflow.map(day => (
                        <div key={`next-${day}`} className="p-2 border-b border-r border-slate-100 dark:border-slate-700/50 bg-slate-50/50 dark:bg-slate-900/30 text-slate-400 dark:text-slate-600">
                             <span className="text-sm font-medium">{day}</span>
                        </div>
                    ))}
                </div>
            </div>
        );
    };

    const renderWeekView = () => {
        const startOfWeek = new Date(currentDate);
        startOfWeek.setDate(currentDate.getDate() - currentDate.getDay()); // Start on Sunday

        const weekDays = Array.from({ length: 7 }).map((_, i) => {
            const d = new Date(startOfWeek);
            d.setDate(startOfWeek.getDate() + i);
            return d;
        });

        return (
            <div className="grid grid-cols-1 md:grid-cols-7 gap-4 animate-fade-in h-full overflow-y-auto">
                {weekDays.map(date => {
                    const key = formatDateKey(date);
                    const count = mockData[key] || 0;
                    const isToday = key === formatDateKey(new Date());

                    return (
                        <div key={key} className={`bg-white dark:bg-slate-800 rounded-xl border p-4 flex flex-col gap-4 ${isToday ? 'border-indigo-500 shadow-md ring-1 ring-indigo-500/20' : 'border-slate-200 dark:border-slate-700'}`}>
                             <div className="text-center pb-2 border-b border-slate-100 dark:border-slate-700">
                                 <div className="text-xs uppercase font-bold text-slate-500 mb-1">{DAYS[date.getDay()]}</div>
                                 <div className={`text-2xl font-bold ${isToday ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-800 dark:text-white'}`}>{date.getDate()}</div>
                             </div>

                             <div className="flex-1 space-y-2">
                                {Array.from({ length: 10 }).map((_, i) => {
                                    const isDone = i < count;
                                    return (
                                        <div key={i} className="flex items-center gap-2">
                                            <div className={`w-4 h-4 rounded-full border flex items-center justify-center ${isDone ? 'bg-indigo-500 border-indigo-500' : 'border-slate-300 dark:border-slate-600'}`}>
                                                {isDone && <svg className="w-3 h-3 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                                            </div>
                                            <div className={`h-2 flex-1 rounded-full ${isDone ? 'bg-indigo-100 dark:bg-indigo-900/30' : 'bg-slate-100 dark:bg-slate-800'}`}></div>
                                        </div>
                                    )
                                })}
                             </div>
                             <div className="text-center text-xs font-semibold text-slate-500">
                                 {count}/10 Completed
                             </div>
                        </div>
                    );
                })}
            </div>
        );
    };

    const renderDayView = () => {
        const key = formatDateKey(currentDate);
        const count = mockData[key] || 0;

        return (
            <div className="max-w-2xl mx-auto animate-fade-in">
                <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
                    <div className="p-8 text-center bg-gradient-to-b from-indigo-50 to-white dark:from-slate-800 dark:to-slate-900 border-b border-slate-100 dark:border-slate-800">
                        <h2 className="text-3xl font-bold text-slate-900 dark:text-white mb-2">{dateString(currentDate)}</h2>
                        <div className="flex items-center justify-center gap-2 mt-4">
                            <span className={`text-4xl font-extrabold ${count === 10 ? 'text-emerald-500' : 'text-indigo-600 dark:text-indigo-400'}`}>{count}</span>
                            <span className="text-xl text-slate-400 font-medium">/ 10</span>
                        </div>
                        <p className="text-slate-500 dark:text-slate-400 mt-2 font-medium">Habits Completed</p>
                    </div>

                    <div className="p-6 sm:p-8 space-y-4">
                        {Array.from({ length: 10 }).map((_, i) => {
                            const isCompleted = i < count;
                            return (
                                <div key={i} className={`flex items-center p-4 rounded-xl border transition-all ${isCompleted ? 'bg-indigo-50 dark:bg-indigo-900/10 border-indigo-100 dark:border-indigo-900/30' : 'bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700'}`}>
                                    <div className={`w-6 h-6 rounded-full border-2 flex items-center justify-center mr-4 transition-colors ${isCompleted ? 'bg-indigo-500 border-indigo-500' : 'border-slate-300 dark:border-slate-600'}`}>
                                        {isCompleted && <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M5 13l4 4L19 7" /></svg>}
                                    </div>
                                    <span className={`font-medium ${isCompleted ? 'text-indigo-900 dark:text-indigo-200 line-through decoration-indigo-300' : 'text-slate-700 dark:text-slate-300'}`}>
                                        Habit Task #{i + 1}
                                    </span>
                                </div>
                            );
                        })}
                    </div>
                </div>
            </div>
        );
    };

    // Helpers
    const dateString = (d: Date) => d.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric', year: 'numeric' });
    const viewLabel = () => {
        if (view === 'year') return currentDate.getFullYear().toString();
        if (view === 'month') return currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' });
        if (view === 'week') return `Week of ${currentDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`;
        return dateString(currentDate);
    };

    return (
        <div className="h-full flex flex-col p-4 sm:p-6 md:p-8 bg-slate-50 dark:bg-slate-900 overflow-hidden">
            {/* Header / Controls */}
            <div className="flex flex-col md:flex-row items-center justify-between gap-4 mb-8 flex-shrink-0">
                <div className="flex items-center gap-4 bg-white dark:bg-slate-800 p-1.5 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700">
                    <button onClick={() => navigate('prev')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-600 dark:text-slate-300 transition-colors">
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <span className="font-bold text-slate-800 dark:text-white min-w-[140px] text-center select-none">
                        {viewLabel()}
                    </span>
                    <button onClick={() => navigate('next')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-600 dark:text-slate-300 transition-colors">
                        <ChevronRight className="w-5 h-5" />
                    </button>
                </div>

                <div className="flex items-center gap-2 bg-slate-200 dark:bg-slate-800 p-1 rounded-xl">
                    {(['year', 'month', 'week', 'day'] as ViewMode[]).map((v) => (
                        <button
                            key={v}
                            onClick={() => setView(v)}
                            className={`px-4 py-2 rounded-lg text-sm font-semibold capitalize transition-all ${
                                view === v 
                                ? 'bg-white dark:bg-slate-600 text-slate-900 dark:text-white shadow-sm' 
                                : 'text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'
                            }`}
                        >
                            {v}
                        </button>
                    ))}
                </div>

                <button 
                    onClick={goToToday}
                    className="px-5 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-500/20 transition-all active:scale-95"
                >
                    Today
                </button>
            </div>

            {/* Content Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar">
                {view === 'year' && renderYearView()}
                {view === 'month' && renderMonthView()}
                {view === 'week' && renderWeekView()}
                {view === 'day' && renderDayView()}
            </div>
        </div>
    );
};

export default HabitCalendar;

