                                    <span className={`text-sm font-bold w-7 h-7 flex items-center justify-center rounded-full ${today ? 'bg-violet-600 text-white shadow-md' : 'text-slate-700 dark:text-slate-300 group-hover:bg-white dark:group-hover:bg-slate-700'}`}>
