    // --- Week View ---
    const WeekView = () => {
        const startOfWeek = new Date(currentDate);
        startOfWeek.setDate(currentDate.getDate() - currentDate.getDay());

        return (
            <div className="grid grid-cols-1 md:grid-cols-7 gap-4 animate-fade-in h-full overflow-y-auto pb-20">
                {Array.from({ length: 7 }).map((_, i) => {
                    const date = new Date(startOfWeek);
                    date.setDate(startOfWeek.getDate() + i);
                    const count = mockData[formatDateKey(date)] || 0;
                    const today = isToday(date);

                    return (
                        <div key={i} className={`flex flex-col bg-white dark:bg-slate-800 rounded-2xl border p-4 shadow-sm transition-all duration-300 hover:-translate-y-1 ${today ? 'border-violet-500 ring-2 ring-violet-500/20' : 'border-slate-200 dark:border-slate-700'}`}>
                            <div className="text-center pb-4 border-b border-slate-100 dark:border-slate-700 mb-4">
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">{DAYS_SHORT[date.getDay()]}</p>
                                <p className={`text-3xl font-black ${today ? 'text-violet-600 dark:text-violet-400' : 'text-slate-800 dark:text-white'}`}>{date.getDate()}</p>
                            </div>

                            <div className="flex-1 space-y-3">
                                <div className="flex items-center justify-between text-xs font-medium text-slate-500 dark:text-slate-400">
                                    <span>Progress</span>
                                    <span>{Math.round((count/10)*100)}%</span>
                                </div>
                                <div className="w-full bg-slate-100 dark:bg-slate-700 rounded-full h-3 overflow-hidden">
                                    <div className={`h-full rounded-full ${getCompletionColor(count)} transition-all duration-1000`} style={{ width: `${(count/10)*100}%` }}></div>
                                </div>
                                <div className="grid grid-cols-5 gap-1 mt-4">
                                    {Array.from({length: 10}).map((_, idx) => (
                                        <div key={idx} className={`h-1.5 rounded-full ${idx < count ? 'bg-violet-500' : 'bg-slate-200 dark:bg-slate-700'}`}></div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )
                })}
            </div>
        );
    };

    // --- Day View ---
    const DayView = () => {
        const count = mockData[formatDateKey(currentDate)] || 0;

        return (
            <div className="max-w-3xl mx-auto animate-fade-in pb-20">
                <div className="bg-white dark:bg-slate-800 rounded-3xl shadow-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
                    <div className="p-8 sm:p-10 text-center bg-gradient-to-b from-violet-50 to-white dark:from-slate-800 dark:to-slate-900/50 border-b border-slate-100 dark:border-slate-800">
                        <div className="inline-flex items-center justify-center p-3 bg-white dark:bg-slate-800 rounded-2xl shadow-lg mb-6">
                            <FlameIcon className={`w-8 h-8 ${getCompletionRingColor(count)}`} />
                        </div>
