                            {currentDate.toLocaleDateString('en-US', { weekday: 'long' })}
                        </h2>
                        <p className="text-lg text-slate-500 dark:text-slate-400 font-medium">
                            {currentDate.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' })}
                        </p>
                    </div>

                    <div className="p-6 sm:p-8 space-y-4">
                        <div className="flex items-center justify-between mb-6">
                            <h3 className="text-lg font-bold text-slate-800 dark:text-white">Daily Habits</h3>
                            <span className="text-sm font-semibold bg-slate-100 dark:bg-slate-700 text-slate-600 dark:text-slate-300 px-3 py-1 rounded-full">
                                {count} / 10 Completed
                            </span>
                        </div>

                        {Array.from({ length: 10 }).map((_, i) => {
                            const isCompleted = i < count;
                            return (
                                <div key={i} className={`flex items-center p-4 rounded-2xl border transition-all duration-300 group ${isCompleted ? 'bg-violet-50/50 dark:bg-violet-900/10 border-violet-100 dark:border-violet-800' : 'bg-white dark:bg-slate-800 border-slate-100 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'}`}>
