const DailyReport: React.FC = () => {
  const [habits, setHabits] = useState<HabitItem[]>(INITIAL_HABITS);
  const [isLocked, setIsLocked] = useState(false);
  const [date, setDate] = useState(new Date());

  const completedCount = useMemo(() => habits.filter(h => h.checked).length, [habits]);
  const progress = (completedCount / 10) * 100;

  // --- State Color Logic ---
  // 0-2: Red, 3-5: Orange, 6-9: Blue, 10: Green
  const colorState = useMemo(() => {
    if (completedCount <= 2) return {
       theme: 'rose', 
       bg: 'bg-rose-500', 
       text: 'text-rose-600', 
       border: 'border-rose-200', 
       light: 'bg-rose-50 dark:bg-rose-900/10',
       label: 'Low Progress'
    };
    if (completedCount <= 5) return { 
       theme: 'orange', 
       bg: 'bg-orange-500', 
       text: 'text-orange-600', 
       border: 'border-orange-200', 
       light: 'bg-orange-50 dark:bg-orange-900/10',
       label: 'Getting There'
    };
    if (completedCount <= 9) return { 
       theme: 'blue', 
       bg: 'bg-blue-500', 
       text: 'text-blue-600', 
       border: 'border-blue-200', 
       light: 'bg-blue-50 dark:bg-blue-900/10',
       label: 'Almost Done'
    };
    return { 
       theme: 'emerald', 
       bg: 'bg-emerald-500', 
       text: 'text-emerald-600', 
       border: 'border-emerald-200', 
       light: 'bg-emerald-50 dark:bg-emerald-900/10',
       label: 'Completed'
    };
  }, [completedCount]);

  // Auto-lock effect when 10/10 is reached
  useEffect(() => {
    if (completedCount === 10 && !isLocked) {
        setIsLocked(true);
    }
  }, [completedCount]);

  const toggleHabit = (id: number) => {
    if (isLocked) return;
    setHabits(prev => prev.map(h => h.id === id ? { ...h, checked: !h.checked } : h));
  };

  const updateLabel = (id: number, newLabel: string) => {
    if (isLocked) return;
    setHabits(prev => prev.map(h => h.id === id ? { ...h, label: newLabel } : h));
  };

  const handleUnlock = () => {
    setIsLocked(false);
  };

  // --- Success View (10/10 Locked) ---
  if (isLocked) {
      return (
        <div className="flex items-center justify-center min-h-[60vh] animate-fade-in px-4">
