interface HabitItem {
  id: number;
  label: string;
  checked: boolean;
}

const HABIT_LABELS = [
    "Wake up by 6:00 AM",
    "Drink 500ml Water",
    "10 min Meditation",
    "Exercise / Gym",
    "Read 10 Pages",
    "Deep Work Session 1",
    "Healthy Lunch",
    "No Social Media (Day)",
    "Plan Tomorrow",
    "Sleep by 10:00 PM"
];

// Helper for deterministic randomness based on date
// This ensures that clicking a date in the calendar always shows the same data
const seededRandom = (seed: number) => {
    const x = Math.sin(seed++) * 10000;
    return x - Math.floor(x);
};

interface DailyReportProps {
  date?: Date;
  readOnly?: boolean;
}

const DailyReport: React.FC<DailyReportProps> = ({ date = new Date(), readOnly = false }) => {
  const [habits, setHabits] = useState<HabitItem[]>([]);
  const [isLocked, setIsLocked] = useState(false);

  // Generate deterministic data based on the date prop
  useEffect(() => {
      const dateKeyStr = date.toISOString().split('T')[0]; // YYYY-MM-DD
      // Create a numeric seed from the date string (removing dashes)
      const seed = parseInt(dateKeyStr.replace(/-/g, ''), 10);
      const isToday = new Date().toDateString() === date.toDateString();

      const generatedHabits = HABIT_LABELS.map((label, index) => {
          // If it's today, we might want a clean slate or specific logic, 
          // but for this demo, we'll use the seed to simulate "state"
          // In a real app, this would fetch from DB.

          // Probability of being checked: 0.6 for past dates
          const isChecked = seededRandom(seed + index * 33) > 0.4;

          return {
              id: index + 1,
              label,
              checked: isChecked
          };
      });

      setHabits(generatedHabits);

      // Auto-lock if all are completed, or explicitly strictly lock past dates if desired
      // For this UX, we'll let the user unlock/edit even past dates for flexibility, unless readOnly is passed
      const allCompleted = generatedHabits.every(h => h.checked);
      setIsLocked(allCompleted);

  }, [date]);

  const completedCount = useMemo(() => habits.filter(h => h.checked).length, [habits]);
  const progress = (completedCount / 10) * 100;

  // --- Strict Color State Logic ---
  // 0-2: Red, 3-5: Orange, 6-9: Blue, 10: Green
  const colorState = useMemo(() => {
    if (completedCount <= 2) return {
       theme: 'rose', 
       bg: 'bg-rose-500', 
       text: 'text-rose-600 dark:text-rose-400', 
       border: 'border-rose-200 dark:border-rose-800', 
       light: 'bg-rose-50 dark:bg-rose-900/20',
       label: 'Low Progress'
    };
    if (completedCount <= 5) return { 
       theme: 'orange', 
       bg: 'bg-orange-500', 
       text: 'text-orange-600 dark:text-orange-400', 
       border: 'border-orange-200 dark:border-orange-800', 
       light: 'bg-orange-50 dark:bg-orange-900/20',
       label: 'Getting There'
    };
    if (completedCount <= 9) return { 
       theme: 'blue', 
       bg: 'bg-blue-500', 
       text: 'text-blue-600 dark:text-blue-400', 
       border: 'border-blue-200 dark:border-blue-800', 
       light: 'bg-blue-50 dark:bg-blue-900/20',
       label: 'Almost Done'
    };
    return { 
       theme: 'emerald', 
       bg: 'bg-emerald-500', 
       text: 'text-emerald-600 dark:text-emerald-400', 
       border: 'border-emerald-200 dark:border-emerald-800', 
       light: 'bg-emerald-50 dark:bg-emerald-900/20',
       label: 'Completed'
    };
  }, [completedCount]);

  const toggleHabit = (id: number) => {
    if (isLocked || readOnly) return;
    setHabits(prev => prev.map(h => h.id === id ? { ...h, checked: !h.checked } : h));
  };

  const updateLabel = (id: number, newLabel: string) => {
    if (isLocked || readOnly) return;
    setHabits(prev => prev.map(h => h.id === id ? { ...h, label: newLabel } : h));
  };

  const handleUnlock = () => {
    if (readOnly) return;
    setIsLocked(false);
  };

  // --- Success View (10/10 Locked) ---
  if (isLocked) {
      return (
        <div className="flex items-center justify-center min-h-[50vh] animate-fade-in px-4 w-full">
            <div className="text-center w-full max-w-sm bg-white dark:bg-slate-800 rounded-3xl p-8 sm:p-10 shadow-xl border border-emerald-100 dark:border-emerald-900/30 relative overflow-hidden">
                 <div className="absolute top-0 left-0 w-full h-1.5 bg-gradient-to-r from-emerald-400 to-green-500"></div>

                 <div className="mb-6 relative inline-block">
                    <div className="absolute inset-0 bg-emerald-100 dark:bg-emerald-900/50 rounded-full animate-ping opacity-75"></div>
                    <CheckCircleIcon className="w-20 h-20 text-emerald-500 relative z-10" />
                 </div>

                 <h2 className="text-2xl sm:text-3xl font-black text-slate-800 dark:text-white mb-2">{completedCount}/10 Achieved!</h2>
                 <p className="text-sm text-slate-500 dark:text-slate-400 mb-8">
                     {date.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
                 </p>

                 <div className="bg-emerald-50 dark:bg-emerald-900/20 rounded-xl p-4 mb-8 border border-emerald-100 dark:border-emerald-900/30">
                     <p className="text-xs font-bold uppercase tracking-widest text-emerald-600 dark:text-emerald-400 mb-1">Status</p>
                     <p className="text-lg font-mono font-bold text-slate-700 dark:text-slate-200">ALL HABITS DONE</p>
                 </div>

                 {!readOnly && (
                     <button 
                        onClick={handleUnlock}
                        className="flex items-center justify-center gap-2 w-full py-3 rounded-xl text-sm font-bold text-slate-500 hover:text-slate-800 dark:text-slate-400 dark:hover:text-white transition-colors hover:bg-slate-100 dark:hover:bg-slate-700"
                     >
                        <LockOpenIcon className="w-4 h-4" />
                        Unlock & Edit Report
                     </button>
                 )}
            </div>
        </div>
      );
  }

  // --- Active View ---
  return (
    <div className="max-w-xl mx-auto w-full pb-10">
        {/* Header Card */}
        <div className={`mb-6 p-5 sm:p-6 rounded-3xl border transition-colors duration-500 bg-white dark:bg-slate-800 shadow-sm ${colorState.border}`}>
            <div className="flex justify-between items-end mb-4">
                <div>
                    <h2 className="text-xs font-bold uppercase tracking-widest text-slate-400 dark:text-slate-500 mb-1">
                        {date.toLocaleDateString('en-US', { weekday: 'long', month: 'long', day: 'numeric' })}
                    </h2>
                    <h1 className="text-xl sm:text-2xl font-extrabold text-slate-900 dark:text-white">Daily Report</h1>
                </div>
                <div className={`px-3 py-1 rounded-full text-xs font-bold uppercase tracking-wide transition-colors duration-500 ${colorState.light} ${colorState.text}`}>
                    {colorState.label}
                </div>
            </div>

            {/* Progress Bar */}
            <div className="relative h-3 bg-slate-100 dark:bg-slate-700 rounded-full overflow-hidden">
                <div 
                    className={`absolute top-0 left-0 h-full rounded-full transition-all duration-700 ease-out ${colorState.bg}`} 
                    style={{ width: `${progress}%` }}
                />
            </div>
            <div className="flex justify-between mt-2 text-xs font-medium text-slate-400">
                <span>0</span>
                <span className={`transition-colors duration-500 ${colorState.text}`}>{completedCount} / 10</span>
                <span>10</span>
            </div>
        </div>

        {/* Habits List */}
        <div className="space-y-3">
            {habits.map((habit) => (
                <div 
                    key={habit.id}
                    className={`group flex items-center p-3 sm:p-4 rounded-xl border bg-white dark:bg-slate-800 transition-all duration-200 ${habit.checked ? 'border-emerald-200 dark:border-emerald-900/30 bg-emerald-50/30 dark:bg-emerald-900/10' : 'border-slate-200 dark:border-slate-700 hover:border-slate-300 dark:hover:border-slate-600'}`}
                >
                    {/* Custom Checkbox */}
                    <button
                        onClick={() => toggleHabit(habit.id)}
                        disabled={readOnly}
                        className={`flex-shrink-0 w-6 h-6 rounded-md border-2 flex items-center justify-center transition-all duration-200 ${habit.checked ? 'bg-emerald-500 border-emerald-500' : 'border-slate-300 dark:border-slate-600 hover:border-indigo-400'}`}
                    >
                        {habit.checked && (
                            <svg className="w-4 h-4 text-white" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={3}>
                                <path strokeLinecap="round" strokeLinejoin="round" d="M5 13l4 4L19 7" />
                            </svg>
                        )}
                    </button>

                    {/* Inline Editable Text */}
                    <input
                        type="text"
                        value={habit.label}
                        onChange={(e) => updateLabel(habit.id, e.target.value)}
                        readOnly={readOnly}
                        className={`flex-1 ml-4 bg-transparent border-none focus:ring-0 p-0 text-base font-medium transition-all w-full ${habit.checked ? 'text-slate-400 dark:text-slate-500 line-through' : 'text-slate-700 dark:text-slate-200'}`}
                        placeholder="Enter habit name..."
                    />

                    {/* Edit Indicator */}
                    {!readOnly && (
                        <div className="opacity-0 group-hover:opacity-100 group-focus-within:opacity-100 transition-opacity text-slate-300 dark:text-slate-600">
                            <PencilIcon className="w-4 h-4" />
                        </div>
                    )}
                </div>
            ))}
        </div>

        {/* Footer Action */}
        {!readOnly && (
            <div className="mt-8 text-center">
                <button 
                    disabled={completedCount === 0}
                    className="w-full sm:w-auto px-8 py-3 rounded-full font-bold text-sm text-white bg-slate-900 dark:bg-white dark:text-slate-900 disabled:opacity-50 disabled:cursor-not-allowed shadow-lg hover:shadow-xl hover:scale-105 transition-all active:scale-95"
                >
                    {completedCount === 0 ? 'Complete a habit first' : 'Update Status'}
                </button>
            </div>
        )}
    </div>
  );
};

