import React, { useState, useMemo } from 'react';
import DailyReport from './DailyReport';

// --- Icons ---
const ChevronLeft = (props: React.SVGProps<SVGSVGElement>) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" {...props}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
  </svg>
);
const ChevronRight = (props: React.SVGProps<SVGSVGElement>) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" {...props}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 4.5l7.5 7.5-7.5 7.5" />
  </svg>
);

type ViewMode = 'year' | 'month' | 'week' | 'day';

const DAYS_SHORT = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
const MONTHS = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

// Seeded Random Helper (Must match DailyReport.tsx)
const seededRandom = (seed: number) => {
    const x = Math.sin(seed++) * 10000;
    return x - Math.floor(x);
};

// --- Data Generator ---
// Uses deterministic seed to match the DailyReport logic perfectly
const generateMockData = (year: number) => {
    const data: Record<string, number> = {};
    const startDate = new Date(year, 0, 1);
    const endDate = new Date(year, 11, 31);

    for (let d = new Date(startDate); d <= endDate; d.setDate(d.getDate() + 1)) {
        const dateStr = d.toISOString().split('T')[0];
        const seed = parseInt(dateStr.replace(/-/g, ''), 10);

        // Use same probablity logic as DailyReport to generate count
        let count = 0;
        for (let i = 0; i < 10; i++) {
             // 0.4 threshold matches DailyReport logic
             if (seededRandom(seed + i * 33) > 0.4) { 
                 count++;
             }
        }
        data[dateStr] = count;
    }
    return data;
};

// Unified Color Logic
// 0-2: Red, 3-5: Orange, 6-9: Blue, 10: Green
const getCompletionColor = (count: number | undefined) => {
    if (count === undefined) return 'bg-slate-100 dark:bg-slate-800/50 text-transparent';
    if (count === 10) return 'bg-emerald-500 text-white shadow-emerald-500/30'; // Green
    if (count >= 6) return 'bg-blue-500 text-white shadow-blue-500/30'; // Blue
    if (count >= 3) return 'bg-orange-500 text-white shadow-orange-500/30'; // Orange
    if (count > 0) return 'bg-rose-500 text-white shadow-rose-500/30'; // Red
    return 'bg-slate-200 dark:bg-slate-700 text-slate-400'; // 0
};

const HabitCalendar: React.FC = () => {
    const [view, setView] = useState<ViewMode>('month');
    const [currentDate, setCurrentDate] = useState(new Date());

    const mockData = useMemo(() => generateMockData(currentDate.getFullYear()), [currentDate.getFullYear()]);

    const navigate = (direction: 'prev' | 'next') => {
        const newDate = new Date(currentDate);
        if (view === 'year') {
            newDate.setFullYear(newDate.getFullYear() + (direction === 'next' ? 1 : -1));
        } else if (view === 'month') {
            newDate.setMonth(newDate.getMonth() + (direction === 'next' ? 1 : -1));
        } else if (view === 'week') {
            newDate.setDate(newDate.getDate() + (direction === 'next' ? 7 : -7));
        } else {
            newDate.setDate(newDate.getDate() + (direction === 'next' ? 1 : -1));
        }
        setCurrentDate(newDate);
    };

    const formatDateKey = (date: Date) => date.toISOString().split('T')[0];
    const isToday = (date: Date) => formatDateKey(date) === formatDateKey(new Date());

    const goToToday = () => {
        const today = new Date();
        setCurrentDate(today);
        if (view === 'year') setView('month');
    };

    const goBack = () => {
        if (view === 'day') setView('month');
        else if (view === 'month') setView('year');
        else if (view === 'week') setView('month');
    };

    // --- Year View ---
    const YearView = () => (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-4 sm:gap-6 animate-fade-in pb-20">
            {MONTHS.map((month, mIdx) => {
                const firstDay = new Date(currentDate.getFullYear(), mIdx, 1);
                const daysInMonth = new Date(currentDate.getFullYear(), mIdx + 1, 0).getDate();
                const offset = firstDay.getDay();

                return (
                    <button 
                        key={month} 
                        onClick={() => {
                            const newDate = new Date(currentDate);
                            newDate.setMonth(mIdx);
                            setCurrentDate(newDate);
                            setView('month');
                        }}
                        className="bg-white dark:bg-slate-800 rounded-2xl p-4 border border-slate-200 dark:border-slate-700 hover:border-indigo-500 dark:hover:border-indigo-500 hover:shadow-lg transition-all text-left group flex flex-col h-full"
                    >
                        <div className="flex justify-between items-center mb-3">
                            <h3 className="font-bold text-slate-800 dark:text-slate-100">{month}</h3>
                        </div>
                        <div className="grid grid-cols-7 gap-1 flex-1 content-start">
                            {/* Weekday headers tiny */}
                            {['S','M','T','W','T','F','S'].map(d => <span key={d} className="text-[8px] text-center text-slate-400 font-bold">{d}</span>)}

                            {Array.from({ length: offset }).map((_, i) => <div key={`empty-${i}`} />)}
                            {Array.from({ length: daysInMonth }).map((_, d) => {
                                const dayDate = new Date(currentDate.getFullYear(), mIdx, d + 1);
                                const count = mockData[formatDateKey(dayDate)];
                                return (
                                    <div 
                                        key={d} 
                                        className={`aspect-square rounded-[2px] w-full ${getCompletionColor(count)}`} 
                                        title={`${dayDate.toDateString()}: ${count}/10`}
                                    />
                                );
                            })}
                        </div>
                    </button>
                );
            })}
        </div>
    );

    // --- Month View ---
    const MonthView = () => {
        const year = currentDate.getFullYear();
        const month = currentDate.getMonth();
        const firstDay = new Date(year, month, 1);
        const daysInMonth = new Date(year, month + 1, 0).getDate();
        const offset = firstDay.getDay();
        const totalSlots = Math.ceil((offset + daysInMonth) / 7) * 7;

        return (
            <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden animate-fade-in h-full flex flex-col">
                <div className="grid grid-cols-7 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
                    {DAYS_SHORT.map(day => (
                        <div key={day} className="py-2 sm:py-3 text-center text-[10px] sm:text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400">
                            {day}
                        </div>
                    ))}
                </div>
                <div className="grid grid-cols-7 flex-1 auto-rows-fr">
                    {Array.from({ length: totalSlots }).map((_, i) => {
                        const dayNum = i - offset + 1;
                        if (dayNum <= 0 || dayNum > daysInMonth) {
                            return <div key={i} className="bg-slate-50/30 dark:bg-slate-900/20 border-b border-r border-slate-100 dark:border-slate-700/50" />;
                        }

                        const date = new Date(year, month, dayNum);
                        const count = mockData[formatDateKey(date)];
                        const today = isToday(date);

                        return (
                            <div 
                                key={i} 
                                onClick={() => { setCurrentDate(date); setView('day'); }}
                                className={`group p-1 sm:p-2 border-b border-r border-slate-100 dark:border-slate-700/50 relative hover:bg-slate-50 dark:hover:bg-slate-700/30 cursor-pointer transition-colors flex flex-col justify-between ${today ? 'bg-indigo-50/30 dark:bg-indigo-900/10' : ''}`}
                            >
                                <div className="flex justify-center sm:justify-between items-start">
                                    <span className={`text-[10px] sm:text-sm font-bold w-5 h-5 sm:w-7 sm:h-7 flex items-center justify-center rounded-full ${today ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-700 dark:text-slate-300 group-hover:bg-white dark:group-hover:bg-slate-600'}`}>
                                        {dayNum}
                                    </span>
                                </div>

                                {count !== undefined && (
                                    <div className="mt-1 sm:mt-2 space-y-1">
                                         <div className="h-1 sm:h-1.5 w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                                             <div className={`h-full ${getCompletionColor(count).split(' ')[0]}`} style={{ width: `${(count/10)*100}%` }}></div>
                                         </div>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        );
    };

    // --- Week View ---
    const WeekView = () => {
        const startOfWeek = new Date(currentDate);
        startOfWeek.setDate(currentDate.getDate() - currentDate.getDay());

        return (
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-7 gap-4 animate-fade-in h-full overflow-y-auto pb-20 px-2 sm:px-0">
                {Array.from({ length: 7 }).map((_, i) => {
                    const date = new Date(startOfWeek);
                    date.setDate(startOfWeek.getDate() + i);
                    const count = mockData[formatDateKey(date)] || 0;
                    const today = isToday(date);

                    return (
                        <div 
                             key={i} 
                             onClick={() => { setCurrentDate(date); setView('day'); }}
                             className={`flex flex-col bg-white dark:bg-slate-800 rounded-2xl border p-4 shadow-sm transition-all duration-300 hover:-translate-y-1 cursor-pointer ${today ? 'border-indigo-500 ring-2 ring-indigo-500/20' : 'border-slate-200 dark:border-slate-700'}`}
                        >
                            <div className="text-center pb-4 border-b border-slate-100 dark:border-slate-700 mb-4">
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">{DAYS_SHORT[date.getDay()]}</p>
                                <p className={`text-3xl font-black ${today ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-800 dark:text-white'}`}>{date.getDate()}</p>
                            </div>

                            <div className="flex-1 space-y-3">
                                <div className="flex items-center justify-between text-xs font-medium text-slate-500 dark:text-slate-400">
                                    <span>Progress</span>
                                    <span>{Math.round((count/10)*100)}%</span>
                                </div>
                                <div className="w-full bg-slate-100 dark:bg-slate-700 rounded-full h-3 overflow-hidden">
                                    <div className={`h-full rounded-full ${getCompletionColor(count).split(' ')[0]} transition-all duration-1000`} style={{ width: `${(count/10)*100}%` }}></div>
                                </div>
                                <div className="grid grid-cols-5 gap-1 mt-4">
                                    {Array.from({length: 10}).map((_, idx) => (
                                        <div key={idx} className={`h-1.5 rounded-full ${idx < count ? 'bg-indigo-500' : 'bg-slate-200 dark:bg-slate-700'}`}></div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )
                })}
            </div>
        );
    };

    // --- Day View ---
    const DayView = () => {
        // Reuse the unified DailyReport component with seeded data
        return <DailyReport date={currentDate} />;
    };

    return (
        <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-900 overflow-hidden">
            {/* Header Controls */}
            <div className="p-4 sm:p-6 pb-4 flex flex-col md:flex-row items-center justify-between gap-4 flex-shrink-0 z-10">
                <div className="flex items-center gap-2 bg-white dark:bg-slate-800 p-1 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 w-full md:w-auto justify-between md:justify-start">
                    <button onClick={() => navigate('prev')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-500 dark:text-slate-400 transition-colors">
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <span className="font-bold text-slate-800 dark:text-white min-w-[140px] text-center select-none text-sm sm:text-base">
                        {view === 'year' && currentDate.getFullYear()}
                        {view === 'month' && currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                        {view === 'week' && `Week of ${currentDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`}
                        {view === 'day' && currentDate.toLocaleDateString('en-US', { month: 'long', day: 'numeric' })}
                    </span>
                    <button onClick={() => navigate('next')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-500 dark:text-slate-400 transition-colors">
                        <ChevronRight className="w-5 h-5" />
                    </button>
                </div>

                <div className="flex items-center gap-2 overflow-x-auto hide-scrollbar max-w-full w-full md:w-auto">
                    {/* Back Button logic */}
                    {view !== 'year' && view !== 'month' && (
                        <button 
                            onClick={goBack} 
                            className="px-3 py-1.5 rounded-lg text-sm font-bold bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 text-slate-600 dark:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-700 mr-2 whitespace-nowrap"
                        >
                            &larr; Up
                        </button>
                    )}

                    <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl flex-1 md:flex-none justify-center">
                        {(['year', 'month', 'week', 'day'] as ViewMode[]).map((v) => (
                            <button
                                key={v}
                                onClick={() => setView(v)}
                                className={`px-3 sm:px-4 py-1.5 rounded-lg text-xs sm:text-sm font-bold capitalize transition-all ${
                                    view === v 
                                    ? 'bg-white dark:bg-slate-600 text-slate-900 dark:text-white shadow-sm' 
                                    : 'text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'
                                }`}
                            >
                                {v}
                            </button>
                        ))}
                    </div>
                    <button 
                        onClick={goToToday}
                        className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-500/20 transition-all active:scale-95 whitespace-nowrap"
                    >
                        Today
                    </button>
                </div>
            </div>

            {/* Scrollable Content Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar px-2 sm:px-6 md:px-8">
                {view === 'year' && <YearView />}
                {view === 'month' && <MonthView />}
                {view === 'week' && <WeekView />}
                {view === 'day' && <DayView />}
            </div>
        </div>
    );
};

