    const isToday = (date: Date) => formatDateKey(date) === formatDateKey(new Date());

    const goToToday = () => {
        const today = new Date();
        setCurrentDate(today);
        if (view === 'year') setView('month'); // If in year, zoom to month
        else if (view === 'month') setView('day'); // If in month, go to day
    };

    const goBack = () => {
        if (view === 'day') setView('month');
        else if (view === 'week') setView('month');
        else if (view === 'month') setView('year');
    };

    const handleDayClick = (date: Date) => {
        setCurrentDate(date);
        setIsReportModalOpen(true);
    };

    // --- Year View ---
    const YearView = () => (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-fade-in pb-20">
            {MONTHS.map((month, mIdx) => {
                const firstDay = new Date(currentDate.getFullYear(), mIdx, 1);
                const daysInMonth = new Date(currentDate.getFullYear(), mIdx + 1, 0).getDate();
                const offset = firstDay.getDay();

                return (
                    <div 
                        key={month} 
                        className="bg-white dark:bg-slate-800 rounded-2xl p-4 border border-slate-200 dark:border-slate-700 shadow-sm flex flex-col h-full hover:border-indigo-500/30 transition-colors"
                    >
                        <div 
                            onClick={() => {
                                const newDate = new Date(currentDate);
                                newDate.setMonth(mIdx);
                                setCurrentDate(newDate);
                                setView('month');
                            }}
                            className="flex justify-between items-center mb-3 cursor-pointer group"
                        >
                            <h3 className="font-bold text-slate-800 dark:text-slate-100 text-sm group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{month}</h3>
                            <span className="text-[10px] text-slate-400 opacity-0 group-hover:opacity-100 transition-opacity">Open View &rarr;</span>
                        </div>
                        <div className="grid grid-cols-7 gap-1 flex-1 content-start">
                            {/* Tiny Weekday headers */}
                            {DAYS_SHORT.map((d, i) => <span key={i} className="text-[8px] text-center text-slate-400 font-bold">{d}</span>)}

                            {Array.from({ length: offset }).map((_, i) => <div key={`empty-${i}`} />)}
                            {Array.from({ length: daysInMonth }).map((_, d) => {
                                const dayDate = new Date(currentDate.getFullYear(), mIdx, d + 1);
                                const dateKey = formatDateKey(dayDate);
                                const count = habitStats[dateKey];
                                return (
                                    <div 
                                        key={d} 
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            handleDayClick(dayDate);
                                        }}
                                        className={`aspect-square rounded-[2px] w-full cursor-pointer hover:ring-1 hover:ring-indigo-500 transition-all ${getCompletionColor(count)}`} 
                                        title={`${dayDate.toDateString()}: ${count || 0}/10`}
                                    />
                                );
                            })}
                        </div>
                    </div>
                );
            })}
        </div>
    );

    // --- Month View ---
    const MonthView = () => {
        const year = currentDate.getFullYear();
        const month = currentDate.getMonth();
        const firstDay = new Date(year, month, 1);
        const daysInMonth = new Date(year, month + 1, 0).getDate();
        const offset = firstDay.getDay();
        const totalSlots = Math.ceil((offset + daysInMonth) / 7) * 7;

        return (
            <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden animate-fade-in h-full flex flex-col">
                <div className="grid grid-cols-7 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
                    {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                        <div key={day} className="py-3 text-center text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400">
                            {day}
                        </div>
                    ))}
                </div>
                <div className="grid grid-cols-7 flex-1 auto-rows-fr">
                    {Array.from({ length: totalSlots }).map((_, i) => {
                        const dayNum = i - offset + 1;
                        if (dayNum <= 0 || dayNum > daysInMonth) {
                            return <div key={i} className="bg-slate-50/30 dark:bg-slate-900/20 border-b border-r border-slate-100 dark:border-slate-700/50" />;
                        }

                        const date = new Date(year, month, dayNum);
                        const dateKey = formatDateKey(date);
                        const count = habitStats[dateKey];
                        const today = isToday(date);

                        return (
                            <div 
                                key={i} 
                                onClick={() => handleDayClick(date)}
                                className={`group p-2 border-b border-r border-slate-100 dark:border-slate-700/50 relative hover:bg-slate-50 dark:hover:bg-slate-700/30 cursor-pointer transition-colors flex flex-col justify-between ${today ? 'bg-indigo-50/30 dark:bg-indigo-900/10' : ''}`}
                            >
                                <div className="flex justify-between items-start">
                                    <span className={`text-xs sm:text-sm font-bold w-6 h-6 flex items-center justify-center rounded-full ${today ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-700 dark:text-slate-300 group-hover:bg-white dark:group-hover:bg-slate-600'}`}>
                                        {dayNum}
                                    </span>
                                </div>

                                {count !== undefined && count > 0 && (
                                    <div className="mt-2 space-y-1">
                                         <div className="h-1.5 w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                                             <div className={`h-full ${getCompletionColor(count).split(' ')[0]}`} style={{ width: `${(count/10)*100}%` }}></div>
                                         </div>
                                         <p className="text-[10px] text-right text-slate-400 font-medium">{count}/10</p>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        );
    };

    // --- Week View ---
    const WeekView = () => {
        const startOfWeek = new Date(currentDate);
        startOfWeek.setDate(currentDate.getDate() - currentDate.getDay());

        return (
            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-7 gap-4 animate-fade-in h-full overflow-y-auto pb-20 px-2 sm:px-0">
                {Array.from({ length: 7 }).map((_, i) => {
                    const date = new Date(startOfWeek);
                    date.setDate(startOfWeek.getDate() + i);
                    const count = habitStats[formatDateKey(date)] || 0;
                    const today = isToday(date);

                    return (
                        <div 
                             key={i} 
                             onClick={() => handleDayClick(date)}
                             className={`flex flex-col bg-white dark:bg-slate-800 rounded-2xl border p-4 shadow-sm transition-all duration-300 hover:-translate-y-1 cursor-pointer ${today ? 'border-indigo-500 ring-2 ring-indigo-500/20' : 'border-slate-200 dark:border-slate-700'}`}
                        >
                            <div className="text-center pb-4 border-b border-slate-100 dark:border-slate-700 mb-4">
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">{['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'][date.getDay()]}</p>
                                <p className={`text-3xl font-black ${today ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-800 dark:text-white'}`}>{date.getDate()}</p>
                            </div>

                            <div className="flex-1 space-y-3">
                                <div className="flex items-center justify-between text-xs font-medium text-slate-500 dark:text-slate-400">
                                    <span>Progress</span>
                                    <span>{Math.round((count/10)*100)}%</span>
                                </div>
                                <div className="w-full bg-slate-100 dark:bg-slate-700 rounded-full h-3 overflow-hidden">
                                    <div className={`h-full rounded-full ${getCompletionColor(count).split(' ')[0]} transition-all duration-1000`} style={{ width: `${(count/10)*100}%` }}></div>
                                </div>
                                <div className="grid grid-cols-5 gap-1 mt-4">
                                    {Array.from({length: 10}).map((_, idx) => (
                                        <div key={idx} className={`h-1.5 rounded-full ${idx < count ? 'bg-indigo-500' : 'bg-slate-200 dark:bg-slate-700'}`}></div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )
                })}
            </div>
        );
    };

    // --- Day View (Full Screen) ---
    const DayView = () => {
        // Reuse the unified DailyReport component with seeded data
        return (
            <div className="animate-fade-in flex flex-col h-full">
                <div className="flex items-center gap-2 mb-4 px-2">
                     <button onClick={goBack} className="p-2 bg-white dark:bg-slate-800 rounded-full shadow-sm border border-slate-200 dark:border-slate-700 hover:bg-slate-50 dark:hover:bg-slate-700 transition-colors">
                        <ChevronLeft className="w-5 h-5 text-slate-600 dark:text-slate-300" />
                     </button>
                     <span className="font-bold text-slate-700 dark:text-slate-200">Back to {view === 'day' ? 'Calendar' : 'Previous View'}</span>
                </div>
                <DailyReport date={currentDate} user={user} />
            </div>
        );
    };

    return (
        <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-900 overflow-hidden relative">
            {/* Header Controls */}
            <div className="p-4 sm:p-6 pb-4 flex flex-col md:flex-row items-center justify-between gap-4 flex-shrink-0 z-10">
                <div className="flex items-center gap-2 bg-white dark:bg-slate-800 p-1.5 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 w-full md:w-auto justify-between md:justify-start">
                    <button onClick={() => navigate('prev')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-500 dark:text-slate-400 transition-colors">
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div className="flex items-center gap-2 px-2">
                        <CalendarIcon className="w-5 h-5 text-indigo-500" />
                        <span className="font-bold text-slate-800 dark:text-white min-w-[140px] text-center select-none text-sm sm:text-base">
                            {view === 'year' && currentDate.getFullYear()}
                            {view === 'month' && currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                            {view === 'week' && `Week of ${currentDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`}
                            {view === 'day' && currentDate.toLocaleDateString('en-US', { month: 'long', day: 'numeric' })}
                        </span>
                    </div>
                    <button onClick={() => navigate('next')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-500 dark:text-slate-400 transition-colors">
                        <ChevronRight className="w-5 h-5" />
                    </button>
                </div>

                <div className="flex items-center gap-2 overflow-x-auto hide-scrollbar max-w-full w-full md:w-auto">
                    {/* View Switcher */}
                    <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl flex-1 md:flex-none justify-center">
                        {(['year', 'month', 'week', 'day'] as ViewMode[]).map((v) => (
                            <button
                                key={v}
                                onClick={() => setView(v)}
                                className={`px-3 sm:px-4 py-1.5 rounded-lg text-xs sm:text-sm font-bold capitalize transition-all ${
                                    view === v 
                                    ? 'bg-white dark:bg-slate-600 text-slate-900 dark:text-white shadow-sm' 
                                    : 'text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'
                                }`}
                            >
                                {v}
                            </button>
                        ))}
                    </div>

                    <button 
                        onClick={goToToday}
                        className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-500/20 transition-all active:scale-95 whitespace-nowrap ml-auto md:ml-0"
                    >
                        Today
                    </button>
                </div>
            </div>

            {/* Scrollable Content Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar px-2 sm:px-6 md:px-8">
                {view === 'year' && <YearView />}
                {view === 'month' && <MonthView />}
                {view === 'week' && <WeekView />}
                {view === 'day' && <DayView />}
            </div>

            {/* Daily Report Modal */}
            {isReportModalOpen && (
                <div 
                    className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-fade-in"
                    onClick={() => setIsReportModalOpen(false)}
                >
                    <div 
                        className="bg-white dark:bg-slate-900 w-full max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-slide-up relative border border-slate-200 dark:border-slate-700 max-h-[90vh] flex flex-col"
                        onClick={e => e.stopPropagation()}
                    >
                        {/* Close Button Header */}
                        <div className="absolute top-4 right-4 z-10">
                             <button
                                onClick={() => setIsReportModalOpen(false)}
                                className="p-2 rounded-full bg-slate-100 dark:bg-slate-800/80 text-slate-500 hover:text-slate-800 dark:hover:text-slate-200 transition-colors backdrop-blur-sm shadow-sm"
                            >
                                <XCircleIcon className="w-6 h-6" />
                            </button>
                        </div>

                        {/* Scrollable Content */}
                        <div className="flex-1 overflow-y-auto custom-scrollbar pt-6">
                             <DailyReport date={currentDate} user={user} />
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

export default HabitCalendar;

import React, { useState } from 'react';
import DailyReport from './DailyReport';
import { User } from '../types';
import useLocalStorage from '../hooks/useLocalStorage';
import XCircleIcon from './icons/XCircleIcon';

// --- Icons ---
const ChevronLeft = (props: React.SVGProps<SVGSVGElement>) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" {...props}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
  </svg>
);
const ChevronRight = (props: React.SVGProps<SVGSVGElement>) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2} stroke="currentColor" {...props}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 4.5l7.5 7.5-7.5 7.5" />
  </svg>
);
const CalendarIcon = (props: React.SVGProps<SVGSVGElement>) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" {...props}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M6.75 3v2.25M17.25 3v2.25M3 18.75V7.5a2.25 2.25 0 012.25-2.25h13.5A2.25 2.25 0 0121 7.5v11.25m-18 0h18M9.75 9.75c0 .414-.168.75-.375.75S9 10.164 9 9.75 9.168 9 9.375 9s.375.336.375.75zm-.375 0h.008v.015h-.008V9.75zm5.625 0c0 .414-.168.75-.375.75s-.375-.336-.375-.75.168-.75.375-.75.375.336.375.75zm-.375 0h.008v.015h-.008V9.75z" />
  </svg>
);

type ViewMode = 'year' | 'month' | 'week' | 'day';

const DAYS_SHORT = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];
const MONTHS = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

// Unified Color Logic
// 0-2: Red, 3-5: Orange, 6-9: Blue, 10: Green
const getCompletionColor = (count: number | undefined) => {
    if (count === undefined || count === 0) return 'bg-slate-100 dark:bg-slate-700/30';
    if (count === 10) return 'bg-emerald-500 shadow-[0_0_8px_rgba(16,185,129,0.4)]'; // Green + Glow
    if (count >= 6) return 'bg-blue-500'; // Blue
    if (count >= 3) return 'bg-orange-500'; // Orange
    return 'bg-rose-500'; // Red
};

interface HabitCalendarProps {
    user: User;
}

const HabitCalendar: React.FC<HabitCalendarProps> = ({ user }) => {
    const [view, setView] = useState<ViewMode>('year'); // Default to Year view as requested
    const [currentDate, setCurrentDate] = useState(new Date());
    const [isReportModalOpen, setIsReportModalOpen] = useState(false);

    // Load REAL data from local storage (same key as HabitLayout)
    const [habitStats] = useLocalStorage<Record<string, number>>(`habit_stats_v1_${user?.id || 'guest'}`, {});

    const navigate = (direction: 'prev' | 'next') => {
        const newDate = new Date(currentDate);
        if (view === 'year') {
            newDate.setFullYear(newDate.getFullYear() + (direction === 'next' ? 1 : -1));
        } else if (view === 'month') {
            newDate.setMonth(newDate.getMonth() + (direction === 'next' ? 1 : -1));
        } else if (view === 'week') {
            newDate.setDate(newDate.getDate() + (direction === 'next' ? 7 : -7));
        } else {
            newDate.setDate(newDate.getDate() + (direction === 'next' ? 1 : -1));
        }
        setCurrentDate(newDate);
    };

    const formatDateKey = (date: Date) => date.toISOString().split('T')[0];
    const isToday = (date: Date) => formatDateKey(date) === formatDateKey(new Date());

    const goToToday = () => {
        const today = new Date();
        setCurrentDate(today);
