import React, { useState, useEffect } from 'react';
import { createPortal } from 'react-dom';
import DailyReport from './DailyReport';
import { User } from '../types';
import useLocalStorage from '../hooks/useLocalStorage';
import XCircleIcon from './icons/XCircleIcon';

// --- Icons ---
const ChevronLeft = (props: React.SVGProps<SVGSVGElement>) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" {...props}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M15.75 19.5L8.25 12l7.5-7.5" />
  </svg>
);
const ChevronRight = (props: React.SVGProps<SVGSVGElement>) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={2.5} stroke="currentColor" {...props}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M8.25 4.5l7.5 7.5-7.5 7.5" />
  </svg>
);
const CalendarIcon = (props: React.SVGProps<SVGSVGElement>) => (
  <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" strokeWidth={1.5} stroke="currentColor" {...props}>
    <path strokeLinecap="round" strokeLinejoin="round" d="M6.75 3v2.25M17.25 3v2.25M3 18.75V7.5a2.25 2.25 0 012.25-2.25h13.5A2.25 2.25 0 0121 7.5v11.25m-18 0h18M9.75 9.75c0 .414-.168.75-.375.75S9 10.164 9 9.75 9.168 9 9.375 9s.375.336.375.75zm-.375 0h.008v.015h-.008V9.75zm5.625 0c0 .414-.168.75-.375.75s-.375-.336-.375-.75.168-.75.375-.75.375.336.375.75zm-.375 0h.008v.015h-.008V9.75z" />
  </svg>
);

type ViewMode = 'year' | 'month' | 'week';

const DAYS_SHORT = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];
const MONTHS = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];

const getCompletionColor = (count: number | undefined) => {
    if (count === undefined || count === 0) return 'bg-slate-100 dark:bg-slate-700/30';
    if (count === 10) return 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]';
    if (count >= 6) return 'bg-blue-500';
    if (count >= 3) return 'bg-orange-500';
    return 'bg-rose-500';
};

interface HabitCalendarProps {
    user: User;
}

const HabitCalendar: React.FC<HabitCalendarProps> = ({ user }) => {
    const [view, setView] = useState<ViewMode>('year');
    const [currentDate, setCurrentDate] = useState(new Date());
    const [isReportModalOpen, setIsReportModalOpen] = useState(false);

    const [habitStats] = useLocalStorage<Record<string, number>>(`habit_stats_v1_${user?.id || 'guest'}`, {});

    const navigate = (direction: 'prev' | 'next') => {
        const newDate = new Date(currentDate);
        if (view === 'year') {
            newDate.setFullYear(newDate.getFullYear() + (direction === 'next' ? 1 : -1));
        } else if (view === 'month') {
            newDate.setMonth(newDate.getMonth() + (direction === 'next' ? 1 : -1));
        } else if (view === 'week') {
            newDate.setDate(newDate.getDate() + (direction === 'next' ? 7 : -7));
        }
        setCurrentDate(newDate);
    };

    const formatDateKey = (date: Date) => date.toISOString().split('T')[0];
    const isToday = (date: Date) => formatDateKey(date) === formatDateKey(new Date());

    const goToToday = () => {
        setCurrentDate(new Date());
    };

    const handleDayClick = (date: Date) => {
        setCurrentDate(date);
        setIsReportModalOpen(true);
    };

    // --- Year View ---
    const YearView = () => (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6 animate-fade-in pb-20">
            {MONTHS.map((month, mIdx) => {
                const firstDay = new Date(currentDate.getFullYear(), mIdx, 1);
                const daysInMonth = new Date(currentDate.getFullYear(), mIdx + 1, 0).getDate();
                const offset = firstDay.getDay();

                return (
                    <div 
                        key={month} 
                        className="bg-white dark:bg-slate-800 rounded-2xl p-4 border border-slate-200 dark:border-slate-700 shadow-sm flex flex-col h-full hover:border-indigo-500/30 transition-colors"
                    >
                        <div 
                            onClick={() => {
                                const newDate = new Date(currentDate);
                                newDate.setMonth(mIdx);
                                setCurrentDate(newDate);
                                setView('month');
                            }}
                            className="flex justify-between items-center mb-3 cursor-pointer group"
                        >
                            <h3 className="font-bold text-slate-800 dark:text-slate-100 text-sm group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{month}</h3>
                            <span className="text-[10px] text-slate-400 opacity-0 group-hover:opacity-100 transition-opacity">Open &rarr;</span>
                        </div>
                        <div className="grid grid-cols-7 gap-1 flex-1 content-start">
                            {DAYS_SHORT.map((d, i) => <span key={i} className="text-[8px] text-center text-slate-400 font-bold">{d}</span>)}
                            {Array.from({ length: offset }).map((_, i) => <div key={`empty-${i}`} />)}
                            {Array.from({ length: daysInMonth }).map((_, d) => {
                                const dayDate = new Date(currentDate.getFullYear(), mIdx, d + 1);
                                const dateKey = formatDateKey(dayDate);
                                const count = habitStats[dateKey];
                                const isCurrentDay = isToday(dayDate);
                                return (
                                    <div 
                                        key={d} 
                                        onClick={(e) => {
                                            e.stopPropagation();
                                            handleDayClick(dayDate);
                                        }}
                                        className={`aspect-square rounded-sm w-full cursor-pointer transition-all duration-200 hover:scale-110 ${getCompletionColor(count)} ${isCurrentDay ? 'ring-1 ring-indigo-500 ring-offset-1 dark:ring-offset-slate-800' : 'hover:ring-1 hover:ring-indigo-300'}`} 
                                        title={`${dayDate.toDateString()}: ${count || 0}/10`}
                                    />
                                );
                            })}
                        </div>
                    </div>
                );
            })}
        </div>
    );

    // --- Month View ---
    const MonthView = () => {
        const year = currentDate.getFullYear();
        const month = currentDate.getMonth();
        const firstDay = new Date(year, month, 1);
        const daysInMonth = new Date(year, month + 1, 0).getDate();
        const offset = firstDay.getDay();
        const totalSlots = Math.ceil((offset + daysInMonth) / 7) * 7;

        return (
            <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden animate-fade-in h-full flex flex-col">
                <div className="grid grid-cols-7 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
                    {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                        <div key={day} className="py-3 text-center text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400">
                            {day}
                        </div>
                    ))}
                </div>
                <div className="grid grid-cols-7 flex-1 auto-rows-fr">
                    {Array.from({ length: totalSlots }).map((_, i) => {
                        const dayNum = i - offset + 1;
                        if (dayNum <= 0 || dayNum > daysInMonth) {
                            return <div key={i} className="bg-slate-50/30 dark:bg-slate-900/20 border-b border-r border-slate-100 dark:border-slate-700/50" />;
                        }

                        const date = new Date(year, month, dayNum);
                        const dateKey = formatDateKey(date);
                        const count = habitStats[dateKey];
                        const today = isToday(date);

                        return (
                            <div 
                                key={i} 
                                onClick={(e) => { e.stopPropagation(); handleDayClick(date); }}
                                className={`group p-2 border-b border-r border-slate-100 dark:border-slate-700/50 relative hover:bg-slate-50 dark:hover:bg-slate-700/30 cursor-pointer transition-colors flex flex-col justify-between ${today ? 'bg-indigo-50/30 dark:bg-indigo-900/10' : ''}`}
                            >
                                <div className="flex justify-between items-start">
                                    <span className={`text-xs sm:text-sm font-bold w-7 h-7 flex items-center justify-center rounded-full ${today ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-700 dark:text-slate-300 group-hover:bg-white dark:group-hover:bg-slate-600'}`}>
                                        {dayNum}
                                    </span>
                                </div>

                                {count !== undefined && count > 0 && (
                                    <div className="mt-2 space-y-1">
                                         <div className="h-1.5 w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                                             <div className={`h-full ${getCompletionColor(count).split(' ')[0]}`} style={{ width: `${(count/10)*100}%` }}></div>
                                         </div>
                                         <p className="text-[10px] text-right text-slate-400 font-medium">{count}/10</p>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        );
    };

    // --- Week View ---
    const WeekView = () => {
        const startOfWeek = new Date(currentDate);
        startOfWeek.setDate(currentDate.getDate() - currentDate.getDay());

        return (
            <div className="grid grid-cols-1 sm:grid-cols-7 gap-4 animate-fade-in h-full overflow-y-auto pb-20 px-2 sm:px-0">
                {Array.from({ length: 7 }).map((_, i) => {
                    const date = new Date(startOfWeek);
                    date.setDate(startOfWeek.getDate() + i);
                    const count = habitStats[formatDateKey(date)] || 0;
                    const today = isToday(date);

                    return (
                        <div 
                             key={i} 
                             onClick={(e) => { e.stopPropagation(); handleDayClick(date); }}
                             className={`flex flex-col bg-white dark:bg-slate-800 rounded-2xl border p-4 shadow-sm transition-all duration-300 hover:-translate-y-1 cursor-pointer ${today ? 'border-indigo-500 ring-2 ring-indigo-500/20' : 'border-slate-200 dark:border-slate-700'}`}
                        >
                            <div className="text-center pb-4 border-b border-slate-100 dark:border-slate-700 mb-4">
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">{['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'][date.getDay()]}</p>
                                <p className={`text-3xl font-black ${today ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-800 dark:text-white'}`}>{date.getDate()}</p>
                            </div>

                            <div className="flex-1 space-y-3">
                                <div className="flex items-center justify-between text-xs font-medium text-slate-500 dark:text-slate-400">
                                    <span>Progress</span>
                                    <span>{Math.round((count/10)*100)}%</span>
                                </div>
                                <div className="w-full bg-slate-100 dark:bg-slate-700 rounded-full h-3 overflow-hidden">
                                    <div className={`h-full rounded-full ${getCompletionColor(count).split(' ')[0]} transition-all duration-1000`} style={{ width: `${(count/10)*100}%` }}></div>
                                </div>
                                <div className="grid grid-cols-5 gap-1 mt-4">
                                    {Array.from({length: 10}).map((_, idx) => (
                                        <div key={idx} className={`h-1.5 rounded-full ${idx < count ? 'bg-indigo-500' : 'bg-slate-200 dark:bg-slate-700'}`}></div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )
                })}
            </div>
        );
    };

    return (
        <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-900 overflow-hidden relative">
            {/* Header Controls */}
            <div className="p-4 sm:p-6 pb-4 flex flex-col md:flex-row items-center justify-between gap-4 flex-shrink-0 z-10 bg-slate-50 dark:bg-slate-900">
                <div className="flex items-center gap-2 bg-white dark:bg-slate-800 p-1.5 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 w-full md:w-auto justify-between md:justify-start">
                    <button onClick={() => navigate('prev')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-500 dark:text-slate-400 transition-colors">
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div className="flex items-center gap-2 px-2">
                        <CalendarIcon className="w-5 h-5 text-indigo-500" />
                        <span className="font-bold text-slate-800 dark:text-white min-w-[140px] text-center select-none text-sm sm:text-base">
                            {view === 'year' && currentDate.getFullYear()}
                            {view === 'month' && currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                            {view === 'week' && `Week of ${currentDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`}
                        </span>
                    </div>
                    <button onClick={() => navigate('next')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-500 dark:text-slate-400 transition-colors">
                        <ChevronRight className="w-5 h-5" />
                    </button>
                </div>

                <div className="flex items-center gap-2 overflow-x-auto hide-scrollbar max-w-full w-full md:w-auto">
                    {/* View Switcher */}
                    <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl flex-1 md:flex-none justify-center">
                        {(['year', 'month', 'week'] as ViewMode[]).map((v) => (
                            <button
                                key={v}
                                onClick={() => setView(v)}
                                className={`px-3 sm:px-4 py-1.5 rounded-lg text-xs sm:text-sm font-bold capitalize transition-all ${
                                    view === v 
                                    ? 'bg-white dark:bg-slate-600 text-slate-900 dark:text-white shadow-sm' 
                                    : 'text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'
                                }`}
                            >
                                {v}
                            </button>
                        ))}
                    </div>

                    <button 
                        onClick={goToToday}
                        className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-500/20 transition-all active:scale-95 whitespace-nowrap ml-auto md:ml-0"
                    >
                        Today
                    </button>
                </div>
            </div>

            {/* Scrollable Content Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar px-2 sm:px-6 md:px-8">
                {view === 'year' && <YearView />}
                {view === 'month' && <MonthView />}
                {view === 'week' && <WeekView />}
            </div>

            {/* SLEEK MODAL: Daily Report */}
            {isReportModalOpen && createPortal(
                <div 
                    className="fixed inset-0 z-[99999] flex items-center justify-center bg-black/60 backdrop-blur-sm animate-fade-in p-4"
                    onClick={() => setIsReportModalOpen(false)}
                >
                    <div 
                        className="bg-white dark:bg-slate-900 w-full max-w-md md:max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-slide-up relative border border-slate-200 dark:border-slate-700 max-h-[90dvh] flex flex-col"
                        onClick={e => e.stopPropagation()}
                    >
                        {/* Header Image/Banner Area */}
                        <div className="h-32 bg-gradient-to-r from-indigo-500 to-purple-600 relative flex-shrink-0">
                            <div className="absolute inset-0 bg-black/10"></div>
                            <div className="absolute -bottom-10 left-6 p-1 bg-white dark:bg-slate-900 rounded-2xl">
                                <div className="w-20 h-20 bg-slate-100 dark:bg-slate-800 rounded-xl flex items-center justify-center text-2xl font-bold text-slate-700 dark:text-slate-300 border border-slate-200 dark:border-slate-700 shadow-sm">
                                    {currentDate.getDate()}
                                </div>
                            </div>
                            <button
                                onClick={() => setIsReportModalOpen(false)}
                                className="absolute top-4 right-4 p-2 rounded-full bg-black/20 hover:bg-black/40 text-white transition-colors backdrop-blur-md"
                            >
                                <XCircleIcon className="w-6 h-6" />
                            </button>
                        </div>

                        {/* Content */}
                        <div className="flex-1 overflow-y-auto custom-scrollbar pt-12 px-6 pb-6">
                            <h2 className="text-2xl font-bold text-slate-900 dark:text-white mb-1">
                                {currentDate.toLocaleDateString('en-US', { weekday: 'long' })}
                            </h2>
                            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
                                {currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                            </p>

                            <DailyReport date={currentDate} user={user} />
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default HabitCalendar;

import React, { useState, useMemo } from 'react';
import HabitNavigation from './HabitNavigation';
import HabitCalendar from './HabitCalendar';
import DailyReport from './DailyReport';
import { User } from '../types';
import useLocalStorage from '../hooks/useLocalStorage';

interface HabitLayoutProps {
  user: User;
  children?: React.ReactNode;
}

const HabitLayout: React.FC<HabitLayoutProps> = ({ user }) => {
  const [activeTab, setActiveTab] = useState('dashboard');

  // Shared stats storage
  const [habitStats, setHabitStats] = useLocalStorage<Record<string, number>>(`habit_stats_v1_${user?.id || 'guest'}`, {});

  // Calculate dashboard metrics based on real data
  const stats = useMemo(() => {
      const dates = Object.keys(habitStats).sort();
      const totalReports = dates.length;

      // Calculate average completion
      const totalHabitsCompleted = Object.values(habitStats).reduce((a, b) => a + b, 0);
      const completionRate = totalReports > 0 ? Math.round((totalHabitsCompleted / (totalReports * 10)) * 100) : 0;

      // Calculate streak
      let streak = 0;
      const today = new Date();
      // Check back from yesterday/today
      let checkDate = new Date(today);
      // Normalize to YYYY-MM-DD
      const toKey = (d: Date) => d.toISOString().split('T')[0];

      // If today has data, start counting from today, else yesterday
      if (!habitStats[toKey(checkDate)]) {
          checkDate.setDate(checkDate.getDate() - 1);
      }

      while (true) {
          const key = toKey(checkDate);
          if (habitStats[key] !== undefined && habitStats[key] > 0) {
              streak++;
              checkDate.setDate(checkDate.getDate() - 1);
          } else {
              break;
          }
      }

      return { streak, completionRate, totalReports };
  }, [habitStats]);

  // Today's progress for sidebar
  const todayKey = new Date().toISOString().split('T')[0];
  const todayCount = habitStats[todayKey] || 0;

  const handleResetProgress = () => {
      if (window.confirm("Are you sure you want to reset all habit data? This cannot be undone.")) {
          setHabitStats({});
          // Note: This doesn't clear the individual day details stored in separate keys, 
          // but removing them from stats effectively hides them from calculation/calendar.
          // A full cleanup would require clearing all localStorage keys matching the pattern,
          // but for this scope, clearing the index (stats) is sufficient to "reset" the view.
          window.location.reload(); // Simple refresh to ensure all child components reset state
      }
  };

  const renderContent = () => {
      switch(activeTab) {
          case 'dashboard':
              return (
                  <div className="p-6 md:p-10 max-w-7xl mx-auto animate-fade-in pb-24">
                      <header className="mb-10">
                          <h1 className="text-3xl font-extrabold text-slate-900 dark:text-white mb-2">Habit Dashboard</h1>
                          <p className="text-slate-500 dark:text-slate-400">Track your consistency and build a better version of yourself.</p>
                      </header>

                      <div className="grid grid-cols-1 sm:grid-cols-3 gap-6 mb-10">
                          <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 relative overflow-hidden group">
                              <div className="absolute top-0 right-0 w-24 h-24 bg-violet-500/10 rounded-bl-full -mr-4 -mt-4 transition-transform group-hover:scale-110"></div>
                              <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2 relative z-10">Current Streak</p>
                              <p className="text-4xl font-black text-violet-600 dark:text-violet-400 relative z-10">{stats.streak} <span className="text-lg font-medium text-slate-400">Days</span></p>
                          </div>
                          <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 relative overflow-hidden group">
                               <div className="absolute top-0 right-0 w-24 h-24 bg-emerald-500/10 rounded-bl-full -mr-4 -mt-4 transition-transform group-hover:scale-110"></div>
                              <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2 relative z-10">Completion Rate</p>
                              <p className="text-4xl font-black text-emerald-600 dark:text-emerald-400 relative z-10">{stats.completionRate}%</p>
                          </div>
                          <div className="bg-white dark:bg-slate-800 p-6 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 relative overflow-hidden group">
                               <div className="absolute top-0 right-0 w-24 h-24 bg-blue-500/10 rounded-bl-full -mr-4 -mt-4 transition-transform group-hover:scale-110"></div>
                              <p className="text-sm font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-2 relative z-10">Total Reports</p>
                              <p className="text-4xl font-black text-slate-800 dark:text-slate-200 relative z-10">{stats.totalReports}</p>
                          </div>
                      </div>

                      <div className="bg-white dark:bg-slate-800 rounded-2xl border border-slate-200 dark:border-slate-700 p-8 text-center">
                           <div className="max-w-md mx-auto">
                               <h3 className="text-xl font-bold text-slate-800 dark:text-white mb-2">Consistency is Key</h3>
                               <p className="text-slate-500 dark:text-slate-400 mb-6">
                                   {stats.streak > 0 
                                     ? `You're on a ${stats.streak} day streak! Keep it up!` 
                                     : "Start your streak today by completing your daily habits."}
                               </p>
                               <div className="w-full bg-slate-100 dark:bg-slate-700 rounded-full h-4 overflow-hidden mb-2">
                                   <div className="bg-gradient-to-r from-violet-500 to-fuchsia-500 h-full rounded-full animate-pulse transition-all duration-1000" style={{ width: `${Math.min(stats.streak * 10, 100)}%` }}></div>
                               </div>
                               <p className="text-xs font-bold text-slate-400 uppercase tracking-widest text-right">{Math.min(stats.streak * 10, 100)}% to Milestone</p>
                           </div>
                      </div>
                  </div>
              );
          case 'calendar':
               // Explicit height wrapper for the calendar to ensure it fills the pane
               return (
                   <div className="h-full w-full flex flex-col">
                       <HabitCalendar user={user} />
                   </div>
               );
          case 'today':
               return (
                  <div className="p-6 md:p-10 animate-fade-in">
                      <DailyReport user={user} />
                  </div>
              );
          case 'history':
              return (
                  <div className="p-6 md:p-10 animate-fade-in pb-24">
                      <h1 className="text-2xl font-bold mb-6 text-slate-900 dark:text-white">Report History</h1>
                      <div className="space-y-4">
                          {Object.entries(habitStats)
                             .sort((a, b) => new Date(b[0]).getTime() - new Date(a[0]).getTime())
                             .map(([date, count]) => (
                              <div key={date} className="bg-white dark:bg-slate-800 p-4 rounded-xl border border-slate-200 dark:border-slate-700 flex justify-between items-center">
                                  <div>
                                      <p className="font-bold text-slate-800 dark:text-white">Daily Report</p>
                                      <p className="text-sm text-slate-500">{new Date(date).toLocaleDateString('en-US', { weekday: 'short', month: 'long', day: 'numeric', year: 'numeric' })}</p>
                                  </div>
                                  <span className={`px-3 py-1 text-xs font-bold rounded-full uppercase ${
                                      count === 10 ? 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300' :
                                      count >= 6 ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300' :
                                      count >= 3 ? 'bg-orange-100 dark:bg-orange-900/30 text-orange-700 dark:text-orange-300' :
                                      'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300'
                                  }`}>
                                      {count}/10 Completed
                                  </span>
                              </div>
                          ))}
                          {Object.keys(habitStats).length === 0 && (
                              <p className="text-center text-slate-500 py-10">No history available yet.</p>
                          )}
                      </div>
                  </div>
              );
          case 'settings':
              return (
                  <div className="p-6 md:p-10 animate-fade-in pb-24">
                      <h1 className="text-2xl font-bold mb-6 text-slate-900 dark:text-white">Habit Settings</h1>
                      <div className="bg-white dark:bg-slate-800 rounded-xl border border-slate-200 dark:border-slate-700 overflow-hidden">
                          <div className="p-6 border-b border-slate-100 dark:border-slate-700/50">
                              <h3 className="font-bold text-slate-800 dark:text-white mb-1">Notifications</h3>
                              <p className="text-sm text-slate-500 mb-4">Manage your daily reminders.</p>
                              <div className="flex items-center justify-between">
                                  <span className="text-sm font-medium">Daily Reminder</span>
                                  <div className="w-10 h-6 bg-violet-600 rounded-full relative"><div className="absolute right-1 top-1 w-4 h-4 bg-white rounded-full"></div></div>
                              </div>
                          </div>
                          <div className="p-6">
                              <h3 className="font-bold text-slate-800 dark:text-white mb-1">Danger Zone</h3>
                              <p className="text-sm text-slate-500 mb-4">Clear all habit data and start fresh.</p>
                              <button onClick={handleResetProgress} className="px-4 py-2 bg-red-100 hover:bg-red-200 text-red-600 dark:bg-red-900/20 dark:hover:bg-red-900/30 dark:text-red-400 font-bold text-sm rounded-lg transition-colors">
                                  Reset All Progress
                              </button>
                          </div>
                      </div>
                  </div>
              );
          default:
              return null;
      }
  }

  return (
    <div className="flex h-full w-full bg-slate-50 dark:bg-slate-950 overflow-hidden relative">
      <HabitNavigation activeTab={activeTab} onNavigate={setActiveTab} />

      {/* Sidebar Stats (Desktop Only) */}
      <div className="hidden">
           {/* Used for calculating the mini progress bar in the nav */}
           <div data-today-count={todayCount}></div> 
      </div>

      <main className="flex-1 overflow-y-auto h-full relative scroll-smooth bg-slate-50 dark:bg-slate-950">
         {renderContent()}
      </main>
    </div>
  );
};

