const HabitNavigation: React.FC<HabitNavigationProps> = ({ activeTab, onNavigate, todayCount }) => {
  const navItems: NavItem[] = [
    { id: 'dashboard', label: 'Dashboard', icon: <DashboardIcon className="w-6 h-6" /> },
    { id: 'calendar', label: 'Calendar', icon: <CalendarIcon className="w-6 h-6" /> },
    { id: 'today', label: 'Today', icon: <CheckListIcon className="w-6 h-6" /> },
    { id: 'history', label: 'History', icon: <HistoryIcon className="w-6 h-6" /> },
    { id: 'settings', label: 'Settings', icon: <SettingsIcon className="w-6 h-6" /> },
  ];

  const getItemClasses = (item: NavItem, isMobile: boolean) => {
    const isActive = activeTab === item.id;
    const isMainAction = item.id === 'today';

    if (isMobile) {
      if (isMainAction) {
        return `flex flex-col items-center justify-center w-14 h-14 rounded-full -mt-6 shadow-lg border-4 border-white dark:border-slate-900 transition-transform active:scale-95 ${
          isActive 
            ? 'bg-violet-600 text-white' 
            : 'bg-slate-900 dark:bg-slate-700 text-white'
        }`;
      }
      return `flex flex-col items-center justify-center w-full h-full space-y-1 transition-colors ${
        isActive 
          ? 'text-violet-600 dark:text-violet-400' 
          : 'text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300'
      }`;
    } else {
      return `flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 group w-full text-left ${
        isActive
          ? 'bg-violet-50 dark:bg-violet-900/20 text-violet-700 dark:text-violet-300 font-semibold shadow-sm'
          : 'text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800/50 hover:text-slate-900 dark:hover:text-slate-200'
      }`;
    }
  };

  const progressPercentage = Math.min(Math.round((todayCount / 10) * 100), 100);

  return (
    <>
      {/* Desktop Sidebar */}
      <aside className="hidden md:flex flex-col w-64 h-full bg-white dark:bg-slate-900 border-r border-slate-200 dark:border-slate-800 flex-shrink-0 z-20">
        <div className="p-6 flex items-center gap-3 border-b border-slate-100 dark:border-slate-800/50">
          <div className="w-8 h-8 bg-violet-600 rounded-lg flex items-center justify-center text-white shadow-lg shadow-violet-500/30">
            <CheckListIcon className="w-5 h-5" />
          </div>
          <span className="font-bold text-lg text-slate-800 dark:text-white tracking-tight">FocusHacker</span>
        </div>

        <nav className="flex-1 px-4 py-6 space-y-2">
          {navItems.map((item) => (
            <button
              key={item.id}
              onClick={() => onNavigate(item.id)}
              className={getItemClasses(item, false)}
            >
              <span className={item.id === 'today' && activeTab !== 'today' ? 'text-violet-600 dark:text-violet-400' : ''}>
                {item.icon}
              </span>
              <span>{item.label}</span>
              {item.id === 'today' && activeTab !== 'today' && (
                <span className="ml-auto flex h-2 w-2 relative">
                   <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-violet-400 opacity-75"></span>
                   <span className="relative inline-flex rounded-full h-2 w-2 bg-violet-500"></span>
                </span>
              )}
            </button>
          ))}
        </nav>

        <div className="p-4 border-t border-slate-100 dark:border-slate-800">
           <div className="bg-slate-50 dark:bg-slate-800/50 p-4 rounded-xl border border-slate-100 dark:border-slate-700/50">
              <div className="flex justify-between items-end mb-2">
                <p className="text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Daily Goal</p>
                <p className="text-xs font-bold text-violet-600 dark:text-violet-400">{todayCount}/10</p>
              </div>
              <div className="w-full bg-slate-200 dark:bg-slate-700 h-2 rounded-full overflow-hidden">
                  <div className="bg-violet-500 h-full rounded-full transition-all duration-500" style={{ width: `${progressPercentage}%` }}></div>
              </div>
           </div>
        </div>
      </aside>

      {/* Mobile Bottom Nav */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 h-16 bg-white/90 dark:bg-slate-900/90 backdrop-blur-md border-t border-slate-200 dark:border-slate-800 z-50 px-2 pb-safe">
        <div className="grid grid-cols-5 h-full items-center relative">
          {navItems.map((item) => (
            <div key={item.id} className="flex justify-center relative">
              <button
                onClick={() => onNavigate(item.id)}
                className={getItemClasses(item, true)}
              >
                {item.icon}
                {item.id !== 'today' && (
                    <span className="text-[10px] font-medium mt-1">{item.label}</span>
                )}
              </button>
            </div>
          ))}
        </div>
      </nav>
    </>
  );
};

