                                                {new Date(date).toLocaleDateString('en-US', { weekday: 'short', month: 'long', day: 'numeric' })}
                                            </p>
                                            <p className="text-xs text-slate-500">{new Date(date).getFullYear()}</p>
                                        </div>
                                        <div className="flex items-center gap-3">
                                             <div className="w-24 bg-slate-100 dark:bg-slate-700 rounded-full h-2 overflow-hidden hidden sm:block">
                                                <div className={`h-full rounded-full ${
                                                     count === 10 ? 'bg-green-500' : count >= 6 ? 'bg-blue-500' : 'bg-orange-500'
                                                }`} style={{ width: `${count * 10}%` }}></div>
                                             </div>
                                            <span className={`px-3 py-1 text-xs font-bold rounded-full uppercase min-w-[100px] text-center ${
                                                count === 10 ? 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300' :
                                                count >= 6 ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300' :
                                                count >= 3 ? 'bg-orange-100 dark:bg-orange-900/30 text-orange-700 dark:text-orange-300' :
                                                'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300'
                                            }`}>
                                                {count}/10 Done
                                            </span>
                                        </div>
                                    </div>
                                ))
                          ) : (
                              <div className="text-center py-20 bg-slate-50 dark:bg-slate-800/50 rounded-2xl border-2 border-dashed border-slate-200 dark:border-slate-700">
                                  <p className="text-slate-500 dark:text-slate-400">No history available yet.</p>
                                  <button onClick={() => setActiveTab('today')} className="mt-4 text-violet-600 font-bold hover:underline">Start Today</button>
                              </div>
                          )}
                      </div>
                  </div>
              );
          case 'settings':
              return (
                  <div className="p-6 md:p-10 animate-fade-in pb-24 h-full overflow-y-auto">
                      <h1 className="text-2xl font-bold mb-6 text-slate-900 dark:text-white">Habit Settings</h1>
