                                  <h3 className="font-bold text-slate-800 dark:text-white mb-1">Daily Goal</h3>
                                  <p className="text-sm text-slate-500 mb-4">Set your target for daily habit completion.</p>
                                  <div className="flex items-center justify-between bg-slate-50 dark:bg-slate-900/50 p-4 rounded-lg">
                                      <span className="text-sm font-medium">Target Habits</span>
                                      <div className="flex items-center gap-4">
                                          <span className="font-bold text-lg">10</span>
                                          <span className="text-xs text-slate-400">(Fixed)</span>
                                      </div>
                                  </div>
                              </div>
                              <div className="p-6">
                                  <h3 className="font-bold text-slate-800 dark:text-white mb-1">Notifications</h3>
                                  <p className="text-sm text-slate-500 mb-4">Manage reminders to build consistency.</p>
                                  <div className="flex items-center justify-between">
                                      <span className="text-sm font-medium">Daily Reminder (9:00 AM)</span>
                                      <button className="w-11 h-6 bg-slate-200 dark:bg-slate-700 rounded-full relative transition-colors cursor-not-allowed opacity-70" disabled title="Feature coming soon">
                                          <div className="absolute left-1 top-1 w-4 h-4 bg-white rounded-full shadow-sm"></div>
                                      </button>
