                          </div>

                          <div className="bg-red-50 dark:bg-red-900/10 rounded-xl border border-red-200 dark:border-red-900/30 p-6">
                              <h3 className="font-bold text-red-800 dark:text-red-200 mb-1">Danger Zone</h3>
                              <p className="text-sm text-red-600 dark:text-red-300/70 mb-4">Irreversible actions for your habit data.</p>
                              <div className="flex items-center justify-between">
                                  <span className="text-sm font-medium text-red-700 dark:text-red-300">Clear All History</span>
                                  <button onClick={handleResetProgress} className="px-4 py-2 bg-white dark:bg-slate-800 border border-red-200 dark:border-red-800 text-red-600 dark:text-red-400 font-bold text-sm rounded-lg hover:bg-red-50 dark:hover:bg-red-900/20 transition-colors shadow-sm">
                                      Reset Progress
                                  </button>
                              </div>
                          </div>
                      </div>
                  </div>
              );
          default:
              return null;
      }
  }

  return (
    <div className="flex h-full w-full bg-slate-50 dark:bg-slate-950 overflow-hidden relative">
      <HabitNavigation activeTab={activeTab} onNavigate={setActiveTab} todayCount={todayCount} />

      <main className="flex-1 overflow-hidden h-full relative bg-slate-50 dark:bg-slate-950">
         {renderContent()}
      </main>
    </div>
  );
};

