    if (count === 10) return 'bg-emerald-500 shadow-[0_0_10px_rgba(16,185,129,0.5)]';
    if (count >= 6) return 'bg-blue-500';
    if (count >= 3) return 'bg-orange-500';
    return 'bg-rose-500';
