                                            handleDayClick(dayDate);
                                        }}
                                        className={`aspect-square rounded-sm w-full cursor-pointer transition-all duration-200 hover:scale-110 ${getCompletionColor(count)} ${isCurrentDay ? 'ring-1 ring-indigo-500 ring-offset-1 dark:ring-offset-slate-800' : 'hover:ring-1 hover:ring-indigo-300'}`} 
                                        title={`${dayDate.toDateString()}: ${count || 0}/10`}
                                    />
                                );
                            })}
                        </div>
                    </div>
                );
            })}
        </div>
    );

    const renderMonthView = () => {
        const year = currentDate.getFullYear();
        const month = currentDate.getMonth();
        const firstDay = new Date(year, month, 1);
        const daysInMonth = new Date(year, month + 1, 0).getDate();
        const offset = firstDay.getDay();
        const totalSlots = Math.ceil((offset + daysInMonth) / 7) * 7;

        return (
            <div className="bg-white dark:bg-slate-800 rounded-2xl shadow-sm border border-slate-200 dark:border-slate-700 overflow-hidden animate-fade-in h-full flex flex-col">
                <div className="grid grid-cols-7 border-b border-slate-200 dark:border-slate-700 bg-slate-50 dark:bg-slate-900/50">
                    {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
                        <div key={day} className="py-3 text-center text-xs font-bold uppercase tracking-wider text-slate-500 dark:text-slate-400">
                            {day}
                        </div>
                    ))}
                </div>
                <div className="grid grid-cols-7 flex-1 auto-rows-fr">
                    {Array.from({ length: totalSlots }).map((_, i) => {
                        const dayNum = i - offset + 1;
                        if (dayNum <= 0 || dayNum > daysInMonth) {
                            return <div key={i} className="bg-slate-50/30 dark:bg-slate-900/20 border-b border-r border-slate-100 dark:border-slate-700/50" />;
                        }

                        const date = new Date(year, month, dayNum);
                        const dateKey = formatDateKey(date);
                        const count = habitStats[dateKey];
                        const today = isToday(date);

                        return (
                            <div 
                                key={i} 
                                onClick={(e) => { e.stopPropagation(); handleDayClick(date); }}
                                className={`group p-2 border-b border-r border-slate-100 dark:border-slate-700/50 relative hover:bg-slate-50 dark:hover:bg-slate-700/30 cursor-pointer transition-colors flex flex-col justify-between ${today ? 'bg-indigo-50/30 dark:bg-indigo-900/10' : ''}`}
                            >
                                <div className="flex justify-between items-start">
                                    <span className={`text-xs sm:text-sm font-bold w-7 h-7 flex items-center justify-center rounded-full ${today ? 'bg-indigo-600 text-white shadow-md' : 'text-slate-700 dark:text-slate-300 group-hover:bg-white dark:group-hover:bg-slate-600'}`}>
                                        {dayNum}
                                    </span>
                                </div>

                                {count !== undefined && count > 0 && (
                                    <div className="mt-2 space-y-1">
                                         <div className="h-1.5 w-full bg-slate-200 dark:bg-slate-700 rounded-full overflow-hidden">
                                             <div className={`h-full ${getCompletionColor(count).split(' ')[0]}`} style={{ width: `${(count/10)*100}%` }}></div>
                                         </div>
                                         <p className="text-[10px] text-right text-slate-400 font-medium">{count}/10</p>
                                    </div>
                                )}
                            </div>
                        );
                    })}
                </div>
            </div>
        );
    };

    const renderWeekView = () => {
        const startOfWeek = new Date(currentDate);
        startOfWeek.setDate(currentDate.getDate() - currentDate.getDay());

        return (
            <div className="grid grid-cols-1 sm:grid-cols-7 gap-4 animate-fade-in h-full overflow-y-auto pb-20 px-2 sm:px-0">
                {Array.from({ length: 7 }).map((_, i) => {
                    const date = new Date(startOfWeek);
                    date.setDate(startOfWeek.getDate() + i);
                    const count = habitStats[formatDateKey(date)] || 0;
                    const today = isToday(date);

                    return (
                        <div 
                             key={i} 
                             onClick={(e) => { e.stopPropagation(); handleDayClick(date); }}
                             className={`flex flex-col bg-white dark:bg-slate-800 rounded-2xl border p-4 shadow-sm transition-all duration-300 hover:-translate-y-1 cursor-pointer ${today ? 'border-indigo-500 ring-2 ring-indigo-500/20' : 'border-slate-200 dark:border-slate-700'}`}
                        >
                            <div className="text-center pb-4 border-b border-slate-100 dark:border-slate-700 mb-4">
                                <p className="text-xs font-bold text-slate-400 uppercase tracking-widest mb-1">{['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'][date.getDay()]}</p>
                                <p className={`text-3xl font-black ${today ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-800 dark:text-white'}`}>{date.getDate()}</p>
                            </div>

                            <div className="flex-1 space-y-3">
                                <div className="flex items-center justify-between text-xs font-medium text-slate-500 dark:text-slate-400">
                                    <span>Progress</span>
                                    <span>{Math.round((count/10)*100)}%</span>
                                </div>
                                <div className="w-full bg-slate-100 dark:bg-slate-700 rounded-full h-3 overflow-hidden">
                                    <div className={`h-full rounded-full ${getCompletionColor(count).split(' ')[0]} transition-all duration-1000`} style={{ width: `${(count/10)*100}%` }}></div>
                                </div>
                                <div className="grid grid-cols-5 gap-1 mt-4">
                                    {Array.from({length: 10}).map((_, idx) => (
                                        <div key={idx} className={`h-1.5 rounded-full ${idx < count ? 'bg-indigo-500' : 'bg-slate-200 dark:bg-slate-700'}`}></div>
                                    ))}
                                </div>
                            </div>
                        </div>
                    )
                })}
            </div>
        );
    };

    return (
        <div className="h-full flex flex-col bg-slate-50 dark:bg-slate-900 overflow-hidden relative">
            {/* Header Controls */}
            <div className="p-4 sm:p-6 pb-4 flex flex-col md:flex-row items-center justify-between gap-4 flex-shrink-0 z-10 bg-slate-50 dark:bg-slate-900">
                <div className="flex items-center gap-2 bg-white dark:bg-slate-800 p-1.5 rounded-xl shadow-sm border border-slate-200 dark:border-slate-700 w-full md:w-auto justify-between md:justify-start">
                    <button onClick={() => navigate('prev')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-500 dark:text-slate-400 transition-colors">
                        <ChevronLeft className="w-5 h-5" />
                    </button>
                    <div className="flex items-center gap-2 px-2">
                        <CalendarIcon className="w-5 h-5 text-indigo-500" />
                        <span className="font-bold text-slate-800 dark:text-white min-w-[140px] text-center select-none text-sm sm:text-base">
                            {view === 'year' && currentDate.getFullYear()}
                            {view === 'month' && currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                            {view === 'week' && `Week of ${currentDate.toLocaleDateString('en-US', { month: 'short', day: 'numeric' })}`}
                        </span>
                    </div>
                    <button onClick={() => navigate('next')} className="p-2 hover:bg-slate-100 dark:hover:bg-slate-700 rounded-lg text-slate-500 dark:text-slate-400 transition-colors">
                        <ChevronRight className="w-5 h-5" />
                    </button>
                </div>

                <div className="flex items-center gap-2 overflow-x-auto hide-scrollbar max-w-full w-full md:w-auto">
                    {/* View Switcher */}
                    <div className="flex bg-slate-200 dark:bg-slate-800 p-1 rounded-xl flex-1 md:flex-none justify-center">
                        {(['year', 'month', 'week'] as ViewMode[]).map((v) => (
                            <button
                                key={v}
                                onClick={() => setView(v)}
                                className={`px-3 sm:px-4 py-1.5 rounded-lg text-xs sm:text-sm font-bold capitalize transition-all ${
                                    view === v 
                                    ? 'bg-white dark:bg-slate-600 text-slate-900 dark:text-white shadow-sm' 
                                    : 'text-slate-500 dark:text-slate-400 hover:text-slate-800 dark:hover:text-slate-200'
                                }`}
                            >
                                {v}
                            </button>
                        ))}
                    </div>

                    <button 
                        onClick={goToToday}
                        className="px-4 py-2 bg-indigo-600 hover:bg-indigo-700 text-white text-sm font-bold rounded-xl shadow-lg shadow-indigo-500/20 transition-all active:scale-95 whitespace-nowrap ml-auto md:ml-0"
                    >
                        Today
                    </button>
                </div>
            </div>

            {/* Scrollable Content Area */}
            <div className="flex-1 overflow-y-auto custom-scrollbar px-2 sm:px-6 md:px-8">
                {view === 'year' && renderYearView()}
                {view === 'month' && renderMonthView()}
                {view === 'week' && renderWeekView()}
            </div>

            {/* SLEEK MODAL: Daily Report */}
            {isReportModalOpen && createPortal(
                <div 
                    className="fixed inset-0 z-[100000] flex items-center justify-center p-4 bg-black/60 backdrop-blur-md animate-fade-in"
                    onClick={() => setIsReportModalOpen(false)}
                >
                    <div 
                        className="bg-white dark:bg-slate-900 w-full max-w-md md:max-w-lg rounded-3xl shadow-2xl overflow-hidden animate-slide-up relative border border-slate-200 dark:border-slate-700 max-h-[90dvh] flex flex-col"
                        onClick={e => e.stopPropagation()}
                    >
                        {/* Header Image/Banner Area */}
                        <div className="h-32 bg-gradient-to-r from-indigo-500 to-purple-600 relative flex-shrink-0">
                            <div className="absolute inset-0 bg-black/10"></div>
                            <div className="absolute -bottom-10 left-6 p-1 bg-white dark:bg-slate-900 rounded-2xl">
                                <div className="w-20 h-20 bg-slate-100 dark:bg-slate-800 rounded-xl flex items-center justify-center text-2xl font-bold text-slate-700 dark:text-slate-300 border border-slate-200 dark:border-slate-700 shadow-sm">
                                    {currentDate.getDate()}
                                </div>
                            </div>
                            <button
                                onClick={() => setIsReportModalOpen(false)}
                                className="absolute top-4 right-4 p-2 rounded-full bg-black/20 hover:bg-black/40 text-white transition-colors backdrop-blur-md"
                            >
                                <XCircleIcon className="w-6 h-6" />
                            </button>
                        </div>

                        {/* Content */}
                        <div className="flex-1 overflow-y-auto custom-scrollbar pt-12 px-6 pb-6">
                            <h2 className="text-2xl font-bold text-slate-900 dark:text-white mb-1">
                                {currentDate.toLocaleDateString('en-US', { weekday: 'long' })}
                            </h2>
                            <p className="text-slate-500 dark:text-slate-400 mb-6 text-sm">
                                {currentDate.toLocaleDateString('en-US', { month: 'long', year: 'numeric' })}
                            </p>

                            <DailyReport date={currentDate} user={user} />
                        </div>
                    </div>
                </div>,
                document.body
            )}
        </div>
    );
};

export default HabitCalendar;
